            ['id' => 14, 'product_category_id' => 2, 'name' => 'Plastic Folding Chair - Non-Stacking - Dark Gray', 'slug' => 'plastic-folding-chair-non-stacking-dark-gray', 'sku' => 'PFC6DG-NS', 'brand' => 'Titan Event Furniture™', 'price' => 27.99, 'stock' => 100, 'image' => 'images/products/plastic-folding-chair-non-stacking-dark-gray/f08413a054cf.jpg', 'gallery' => '["images\\/products\\/plastic-folding-chair-non-stacking-dark-gray\\/f08413a054cf.jpg","images\\/products\\/plastic-folding-chair-non-stacking-dark-gray\\/cb0cdcaa9b9e.jpg","images\\/products\\/plastic-folding-chair-non-stacking-dark-gray\\/f6eb9ed1e936.jpg","images\\/products\\/plastic-folding-chair-non-stacking-dark-gray\\/667c0b08fcca.jpg","images\\/products\\/plastic-folding-chair-non-stacking-dark-gray\\/0b0a9ac88272.jpg","images\\/products\\/plastic-folding-chair-non-stacking-dark-gray\\/44e94e8c10ec.jpg","images\\/products\\/plastic-folding-chair-non-stacking-dark-gray\\/f797ba1f9723.jpg","images\\/products\\/plastic-folding-chair-non-stacking-dark-gray\\/ac036793ae88.jpg"]', 'description' => 'If you\'re looking for a durable and extra comfortable seating option for your next event, look no further than our Titan Series™ Non-Stacking Plastic Folding Chair.', 'features' => '["If you\'re looking for a durable and extra comfortable seating option for your next event, look no further than our Titan Series\\u2122 Non-Stacking Plastic Folding Chair.","Yes, we know how convenient the stacking function is for storage but we had to sacrifice some of those qualities in order to offer a one of a kind, durable, lightweight and enjoyable sitting experience.","The contoured seat sports a 20\'\' x 23\'\' footprint and follows it up with a matching contoured back rest to maximize comfort levels while the steel folding chair frame insures that you\'re getting a product that will hold up from event season to event season.","Last but certainly not least, the most important and impressive function of this commercial-grade chair - clips on the side of each chair that connect to each other so you\'ll always have a straight line, and save much needed time throughout the process of setting up.","No matter the terrain, whether it be outside on a hill or inside at a banquet facilility, this plastic folding chair is truly one of a kind, and will be the perfect addition to your party rental company, event venue, school, church or any place where folks need a dependable and comfortable seat."]', 'specifications' => '{"UPC":"810171060051","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Brand":"Titan Event Furniture\\u2122","Color":"Dark Grey","Material":"Polypropylene","Commercial-Grade?":"Yes","Overall Height":"32.5\'\'","Overall Width":"20\'\'","Overall Length \\/ Depth":"23\'\'","Seat Height":"17.5\'\'","Ships Assembled?":"Yes","Stackable?":"No","Has Arms":"No","Item Weight":"9 lbs","Static Weight Capacity":"1102 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-16 06:01:04', 'updated_at' => '2026-06-18 08:38:17'],
