            ['id' => 16, 'product_category_id' => 2, 'name' => 'Plastic Folding Chair II - Black', 'slug' => 'plastic-folding-chair-ii-black', 'sku' => 'PFC12BK', 'brand' => 'Titan Event Furniture™', 'price' => 15.99, 'stock' => 100, 'image' => 'images/products/plastic-folding-chair-ii-black/b0f94b997e24.png', 'gallery' => '["images\\/products\\/plastic-folding-chair-ii-black\\/b0f94b997e24.png","images\\/products\\/plastic-folding-chair-ii-black\\/8f72f3ea7573.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/a85a9eaf164a.jpeg","images\\/products\\/plastic-folding-chair-ii-black\\/942d968408d3.png","images\\/products\\/plastic-folding-chair-ii-black\\/af2ce4eb91a0.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/52af16bcd39f.jpg"]', 'description' => 'Professional grade TitanPRO™ Plastic Folding Chairs feature a durable, powder coated frame with a comfortable, contoured backrest and seat.', 'features' => '["Professional grade TitanPRO\\u2122 Plastic Folding Chairs feature a durable, powder coated frame with a comfortable, contoured backrest and seat.","Party rental tested and event venue approved.","Suitable for outdoor and indoor use.","Multiple color variations to fit any graduation, ceremony, concert, party, or social function.","Lightweight and easy to clean.","Safely stack up to 50+ chairs high.","If you\'re ready for durable, party rental proven and event ready poly chairs, you\'re ready for our TitanPRO\\u2122 Plastic Folding Chair.","This commercial-grade seating option represents the finest and toughest in event furniture manufacturing while not having to sacrifice that wholesale folding chair price.","These folding chairs can stack in excess of 50 units high and feature a textured polyurethane seat and matching contoured backrest to maximize comfort.","All chairs are available in an array of colors to fully compliment any social function - school graduations, concerts, sports events, ceremonies, or even your own home!.","Combined with a durable powder coated frame that remains lightweight and versatile, our TitanPRO\\u2122 Plastic Folding Chairs actually weigh 1 pound less than our popular Titan Series folding chairs.","We\'re confident this will by far be the most pleasant seating experience that you\'ll find in a plastic folding chair.","Save some bucks by purchasing these folding chairs in bulk.","All of our chairs feature free shipping and quantity pricing deals when you buy in excess of 50+.","While you\'re at it, save some stress and pair stacks of our plastic folding chairs with our Folding Chair Dolly"]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Folded Dimensions":"2.5\'\' x 17.5\'\' x 38\'\'","Overall Height":"31.5\'\'","Overall Width":"18\'\'","Overall Length \\/ Depth":"19\'\'","Seat Height":"17.5\'\'","Seat Material":"Polyurethane","Ships Assembled?":"Yes","Stackable?":"Yes","Has Arms":"No","Product Warranty":"1 Year Warranty","Item Weight":"6.4 lbs.","Static Weight Capacity":"683 lbs.","Dynamic Weight Capacity":"250 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"Can I place a bulk order for Plastic Folding Chairs?","answer":"Yes! In fact, we encourage it and try to make it as easy as possible for our customers to buy plastic folding chairs in bulk. We offer discount bundles of 100, 200, and 300 plastic folding chairs featuring folding chair dollies, ratchet straps and free shipping!"},{"question":"How many chairs can I stack?","answer":"We recommend these chairs stack 50 high on a dolly or 100 chairs high on the floor."},{"question":"What is the best way to clean plastic folding chairs?","answer":"Wipe them down with a cloth or sponge soaked in warm, soapy water. For tougher stains, use a soft-bristle brush. Rinse with clean water and let them air dry. Avoid harsh chemicals like bleach to protect the plastic."},{"question":"How long will plastic folding chairs last with regular care?","answer":"Our commercial-grade plastic folding chairs are built to withstand heavy use in event and hospitality settings. With regular cleaning and proper storage, they can last well over a decade, making them a durable and reliable choice for your business."}]', 'default_color' => 'Black', 'color_variants' => '[{"label":"Brown","swatch":"images\\/products\\/plastic-folding-chair-ii-black\\/16a6d1d71d23.png","gallery":["images\\/products\\/plastic-folding-chair-ii-black\\/4d35128ba81a.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/ef84fca73862.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/97c73b751b54.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/dcd5f6807208.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/420c9f530e5d.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/954db785d3e0.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/c15ead0b1407.jpg"]},{"label":"Black","swatch":"images\\/products\\/plastic-folding-chair-ii-black\\/d889c95969e0.png","gallery":["images\\/products\\/plastic-folding-chair-ii-black\\/b0f94b997e24.png","images\\/products\\/plastic-folding-chair-ii-black\\/8f72f3ea7573.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/a85a9eaf164a.jpeg","images\\/products\\/plastic-folding-chair-ii-black\\/942d968408d3.png","images\\/products\\/plastic-folding-chair-ii-black\\/af2ce4eb91a0.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/52af16bcd39f.jpg"]},{"label":"Burgundy","swatch":"images\\/products\\/plastic-folding-chair-ii-black\\/ead973ef9a86.png","gallery":["images\\/products\\/plastic-folding-chair-ii-black\\/3620929f1504.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/aed230ac563b.jpg","images\\/products\\/plastic-folding-chair-ii-black\\/b76d0ba8bc7a.jpg","images\\/products\\/plastic-folding-chair-ii-b