            ['id' => 18, 'product_category_id' => 2, 'name' => 'Aluminum Plastic Folding Chair - Black', 'slug' => 'aluminum-plastic-folding-chair-black', 'sku' => 'PFC2-ALUM-BK', 'brand' => 'Titan Event Furniture™', 'price' => 28.49, 'stock' => 100, 'image' => 'images/products/aluminum-plastic-folding-chair-black/a055ff270108.jpg', 'gallery' => '["images\\/products\\/aluminum-plastic-folding-chair-black\\/a055ff270108.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/0dfdc85b77ed.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/70475c117c10.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/56363580855a.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/b0500091308b.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/3e0ef2ad1e7d.png"]', 'description' => 'What looks like an ordinary plastic folding chair upon first glance is anything but upon further inspection.', 'features' => '["What looks like an ordinary plastic folding chair upon first glance is anything but upon further inspection.","In fact, The only similarity our TitanPRO Aluminum Plastic Folding Chair has with that generic folding chair used in your third grader\'s classroom is that it keeps you from sitting on the crumb filled floor.","Satisfactory in the moment, sure, but moments don\'t last forever like cold November rain and neither will that cookie cutter $8.99 Samsonite style folding chair from some of our competitors.","What you need is a commercial-grade quality chair that\'s durable, functional and dependable for the present and all your future days.","Adding gas to this fire, the stainless steel hardware and aluminum frame ensures that it\'ll never rust.","Oh, and did we mention that it actually weighs less than your typical plastic folding chair?","At 5 lbs. a chair, that means a stack of 50 on one of our Folding Chair Dollies will weigh 100 lbs than if you were pushing a regular poly chair stack!","Yes, our TitanPRO Aluminum Plastic Folding chair is all that and more."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Frame":"Aluminum","Folded Dimensions":"3\'\' x 17.5\'\' x 38.5\'\'","Overall Height":"31.75\'\'","Overall Width":"17.5\'\'","Seat Height":"17.5\'\'","Ships Assembled?":"Yes","Stackable?":"Yes","Has Arms":"No","Product Warranty":"1 Year","Item Weight":"5 lbs.","Static Weight Capacity":"450 lbs.","Dynamic Weight Capacity":"250 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"How long will plastic folding chairs last with regular care?","answer":"Our commercial-grade plastic folding chairs are built to withstand heavy use in event and hospitality settings. With regular cleaning and proper storage, they can last well over a decade, making them a durable and reliable choice for your business."}]', 'default_color' => 'Black', 'color_variants' => '[{"label":"Black","swatch":"images\\/products\\/aluminum-plastic-folding-chair-black\\/d889c95969e0.png","gallery":["images\\/products\\/aluminum-plastic-folding-chair-black\\/b0500091308b.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/3e0ef2ad1e7d.png"]},{"label":"Charcoal Grey","swatch":"images\\/products\\/aluminum-plastic-folding-chair-black\\/399bd370ad4f.png","gallery":["images\\/products\\/aluminum-plastic-folding-chair-black\\/5c09c6cf2053.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/32f61055025b.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/df558ea44cd9.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/b0500091308b.jpg","images\\/products\\/aluminum-plastic-folding-chair-black\\/3e0ef2ad1e7d.png"]},{"label":"White","swatch":"#ffffff","gallery":["images\\/products\\/aluminum-plastic-folding-chair-black\\/8a32c0909ff6.jpg","images\\/products\\/alu