            ['id' => 20, 'product_category_id' => 2, 'name' => 'Blow Molded White Plastic Folding Chair with Gray Frame', 'slug' => 'blow-molded-white-plastic-folding-chair-with-gray-frame-2', 'sku' => 'BMPFC2GRF', 'brand' => 'Titan Event Furniture™', 'price' => 33.99, 'stock' => 100, 'image' => 'images/products/blow-molded-white-plastic-folding-chair-with-gray-frame-2/656422ee434f.jpg', 'gallery' => '["images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/656422ee434f.jpg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/087c1ba7fcab.jpg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/ad1d892c2a10.jpeg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/667b23fdbae2.jpeg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/76932b7b6e09.jpg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/8dd5d4e43ad6.jpeg"]', 'description' => 'Comfortable event seating has its champion.', 'features' => '["Comfortable event seating has its champion.","This blow molded plastic folding chair features and oversized wide seat and backrest for unparalleled comfort.","The HDPE plastic is water-resistant and easy to clean, while the steel frame is built to withstand up to 500 lbs of weight capacity.","An integrated carrying handle helps to make quick work of event setups.","Below the seat, the curved, ergonomic frame crosspiece allows for extra foot room enhancing the guest\'s comfort.","These chairs look great with our plastic folding tables.","Don\'t forget about storage and transport as well, with a trolley made specifically for this blow molded plastic folding chair.","Click here for the cart"]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Frame":"Steel","Overall Height":"33\'\'","Overall Width":"18.5\'\'","Overall Length \\/ Depth":"22\'\'","Ships Assembled?":"Yes","Has Arms":"No","Product Warranty":"3 Year Warranty","Item Weight":"11.4","Weight Capacity":"500 lbs.","Dynamic Weight Capacity":"250 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => 'White', 'color_variants' => '[{"label":"Black","swatch":"images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/d889c95969e0.png","gallery":["images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/52adc1d6e428.jpeg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/8dd5d4e43ad6.jpeg"]},{"label":"White","swatch":"#ffffff","gallery":["images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/656422ee434f.jpg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/087c1ba7fcab.jpg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/ad1d892c2a10.jpeg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/667b23fdbae2.jpeg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/76932b7b6e09.jpg","images\\/products\\/blow-molded-white-plastic-folding-chair-with-gray-frame-2\\/8dd5d4e43ad6.jpeg"]}]', 'is_active' => 1, 'created_at' => '2026-06-16 06:02:20', 'updated_at' => '2026-06-18 08:21:55'],
            ['id' => 21, 'product_category_id' => 2, 'name' => 'Fanback Plastic Folding Chair - Black', 'slug' => 'fanback-plastic-folding-chair-black', 'sku' => 'FPFC2BK', 'brand' => 'Titan Event Furniture™', 'price' => 18.99, 'stock' => 100, 'image' => 'images/products/fanback-plastic-folding-chair-black/53854a504775.jpg', 'gallery' => '["images\\/products\\/fanback-plastic-folding-chair-black\\/53854a504775.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/e3827b7e1a9c.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/33618c757e9c.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/e09ab1325e35.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/0dd310f3f6a8.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/fec745abacc3.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/6dcd15242edd.jpg"]', 'description' => 'TitanPRO™ Fanback Plastic Folding Chairs add a little bit of character and extra durability to the traditional plastic folding chair.', 'features' => '["TitanPRO\\u2122 Fanback Plastic Folding Chairs add a little bit of character and extra durability to the traditional plastic folding chair.","Made to the same rugged specifications as our commercial-grade TitanPRO\\u2122 poly folding chairs, these are a popular and attactive alternative for graduation and wedding seating.","The chairs feature a strong 18 gauge steel frame and 1st grade polypropylene plastic combined for a commercial quality chair.","The paint finish is an extremely durable baked on powdercoat.","The chairs fold and stack to 50 chairs high for transport or up to 100 chairs high for warehouse storage.","Transport and setup is easy with the integrated carrying handle built into the chair back.","Non-marring feet caps ensure that the chairs can be used indoors or outdoors."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Material":"Plastic","Commercial-Grade?":"Yes","Overall Height":"35\'\'","Overall Width":"17.5\'\'","Overall Length \\/ Depth":"21.5\'\'","Seat Height":"17.5\'\'","Seat Size":"15.5\'\'W x 15.75\'\'D","Ships Assembled?":"Yes","Stackable?":"Yes","Has Arms":"No","Static Weight Capacity":"683 lbs.","Dynamic Weight Capacity":"250 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"How many chairs can I stack?","answer":"We recommend these chairs stack 50 high on a dolly or 100 chairs high on the floor."},{"question":"What is the best way to clean plastic folding chairs?","answer":"Wipe them down with a cloth or sponge soaked in warm, soapy water. For tougher stains, use a soft-bristle brush. Rinse with clean water and let them air dry. Avoid harsh chemicals like bleach to protect the plastic."},{"question":"How long will plastic folding chairs last with regular care?","answer":"Our commercial-grade plastic folding chairs are built to withstand heavy use in event and hospitality settings. With regular cleaning and proper storage, they can last well over a decade, making them a durable and reliable choice for your business."}]', 'default_color' => 'Black', 'color_variants' => '[{"label":"Black","swatch":"images\\/products\\/fanback-plastic-folding-chair-black\\/d889c95969e0.png","gallery":["images\\/products\\/fanback-plastic-folding-chair-black\\/6dcd15242edd.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/c55b0ef6fccb.jpg"]},{"label":"White","swatch":"#ffffff","gallery":["images\\/products\\/fanback-plastic-folding-chair-black\\/53695024e2ef.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/00361f2efcf2.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/3fd3e8821f01.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/5259e671a89e.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/765cd5f6dc94.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/6277c355d715.jpg","images\\/products\\/fanback-plastic-folding-chair-black\\/6dcd15242edd.jpg"]}]', 'is_active' => 1, 'created_at' => '2026-06-16 06:02:33', 'updated_at' => '2026-06-18 08:38:17'],
            ['id' => 22, 'product_category_id' => 2, 'name' => 'Plastic Folding Chair with Drain Holes - Light Gray', 'slug' => 'plastic-folding-chair-with-drain-holes-light-gray', 'sku' => 'PFC2LGRY-DH', 'brand' => 'Titan Event Furniture™', 'price' => 15.99, 'stock' => 100, 'image' => 'images/products/plastic-folding-chair-with-drain-holes-light-gray/2c273298e528.jpg', 'gallery' => '["images\\/products\\/plastic-folding-chair-with-drain-holes-light-gray\\/2c273298e528.jpg","images\\/products\\/plastic-folding-chair-with-drain-holes-light-gray\\/b6924b4214f6.jpg","images\\/products\\/plastic-folding-chair-with-drain-holes-light-gray\\/215dbf570b61.jpg","images\\/products\\/plastic-folding-chair-with-drain-holes-light-gray\\/fbb12b9b6522.jpg","images\\/products\\/plastic-folding-chair-with-drain-holes-light-gray\\/2a328fcb89db.jpg","images\\/products\\/plastic-folding-chair-with-drain-holes-light-gray\\/26f67b57ded5.jpg","images\\/products\\/plastic-folding-chair-with-drain-holes-light-gray\\/510616b093bd.jpg"]', 'description' => 'Our TitanPRO™ Plastic Folding Chair with Drain Holes is a commercial-grade, stackable seating solution designed for both indoor and outdoor use.', 'features' => '["Our TitanPRO\\u2122 Plastic Folding Chair with Drain Holes is a commercial-grade, stackable seating solution designed for both indoor and outdoor use.","Crafted from the same durable polypropylene as our flagship TitanPRO\\u2122 Plastic Folding Chairs, it features a vented seat with drain holes, allowing for quick water runoff and easy cleaning.","Its lightweight yet sturdy frame ensures effortless transport and setup, making it a practical choice for event venues and party rental businesses.","With a 17.5\'\' seat height and ergonomic design, this chair also offers comfort and reliability for any occasion.","These chairs stack easily and compactly, fitting securely on our folding chair dolly for smooth transport and efficient storage.","Best of all, it ships free when you buy 50