            ['id' => 37, 'product_category_id' => 29, 'name' => 'Sonoma Cross Back Chair - Dark Walnut', 'slug' => 'sonoma-cross-back-chair-dark-walnut', 'sku' => 'SXBC-C4-DW', 'brand' => 'CSP', 'price' => 81.49, 'stock' => 100, 'image' => 'images/products/sonoma-cross-back-chair-dark-walnut/292ff677d54f.png', 'gallery' => '["images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/292ff677d54f.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/41c8c744a0aa.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/dfa1e17c0782.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/a3a5e3794b81.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/b6fd4a8391cf.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/206005730114.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/862ccce8f4a3.jpg"]', 'description' => 'Sonoma Oak Cross Back Bar Stools also available - See them here', 'features' => '["Sonoma Oak Cross Back Bar Stools also available - See them here","The Sonoma Cross Back Chair invites a sense of timeless heritage into your space, bridging the gap between rugged farmhouse charm and sophisticated elegance.","Carved from genuine solid hardwood oak, each piece serves as a testament to natural beauty, featuring a weathered antique finish that highlights the unique character of the wood grain.","This chair is not merely a seat but a design statement, offering an inviting warmth that transforms any indoor dining environment into a curated experience.","Beyond its aesthetic appeal, the Sonoma is engineered for the high-energy demands of commercial hospitality.","The signature cross-back silhouette is thoughtfully contoured to provide ergonomic support, ensuring that guests remain comfortable from the first course to the final toast.","While the design looks delicate and historic, the solid oak construction provides a sturdy, dependable foundation built to endure years of consistent use.","Functionality remains at the heart of the Sonoma design, particularly for venues that require frequent transitions.","These chairs stack seamlessly up to eight high, allowing for effortless reconfiguration and compact storage when the floor needs to be cleared.","By combining the soul of traditional craftsmanship with the practical needs of modern event management, the Sonoma Cross Back Chair offers a durable, space-saving solution that never compromises on style."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Brand":"CSP","Material":"Elm Wood","Commercial-Grade?":"Yes","Overall Height":"35\'\'","Overall Width":"17.5\'\'","Overall Length \\/ Depth":"16.25\'\'","Seat Height":"18\'\'","Seat Material":"Oak Wood","Ships Assembled?":"Yes","Stackable?":"Yes","Has Arms":"No","Item Weight":"11 lbs.","Weight Capacity":"500 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => 'Dark Walnut', 'color_variants' => '[{"label":"Dark Walnut","swatch":"images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/f99d22291756.png","gallery":["images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/292ff677d54f.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/41c8c744a0aa.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/dfa1e17c0782.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/a3a5e3794b81.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/b6fd4a8391cf.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/206005730114.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/862ccce8f4a3.jpg"]},{"label":"Dark","swatch":"#381e06","gallery":["images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/de2c3d6e71dc.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/d66d881f4412.png","images\\/products\\/sonoma-cross-back-chair-dark-walnut\\/d6d8329ff70b.png","i