"No","Weight Capacity":"200 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 04:20:31', 'updated_at' => '2026-06-18 11:38:01'],
