            ['id' => 67, 'product_category_id' => 40, 'name' => 'Industrial Metal Bar Stool - Black', 'slug' => 'industrial-metal-bar-stool-black', 'sku' => 'MBS9BLK', 'brand' => NULL, 'price' => 78.99, 'stock' => 100, 'image' => 'images/products/industrial-metal-bar-stool-black/006a9d6c23b2.jpg', 'gallery' => '["images\\/products\\/industrial-metal-bar-stool-black\\/006a9d6c23b2.jpg","images\\/products\\/industrial-metal-bar-stool-black\\/0a4fb3a7f953.jpg","images\\/products\\/industrial-metal-bar-stool-black\\/dfcd66dcdc9f.jpg","images\\/products\\/industrial-metal-bar-stool-black\\/b55f9f19cc9d.jpg","images\\/products\\/industrial-metal-bar-stool-black\\/0f7e2628b575.jpg","images\\/products\\/industrial-metal-bar-stool-black\\/099f699aceaa.jpg"]', 'description' => 'Outfit your event venue, brewery, cafe, barber shop, or even your home in strong and durable industrial excellence with our 30\'\' Titan Series™ Metal Bar Stool.', 'features' => '["Outfit your event venue, brewery, cafe, barber shop, or even your home in strong and durable industrial excellence with our 30\'\' Titan Series\\u2122 Metal Bar Stool.","This backless bar stool sits at the perfect height for any bar seating or saddled up next to any standard cocktail table.","And because these barstools were made with the event and hospitality industry in mind, each stool easily stacks 4 to 8 high when they\'re not being used and the 11 lb frame makes them even easier to carry.","Indoors or outdoors, these sturdy yet lightweight metal bar stools are the ultimate choice if you\'re looking for a more modern approach to your venue."]', 'specifications' => '{"Can ship FedEx?":"Yes","Material":"Metal","Commercial-Grade?":"Yes","Overall Width":"17\'\'","Overall Height":"30\'\'","Overall Length \\/ Depth":"17\'\'","Seat Height":"30\'\'","Ships Assembled?":"Yes","Stackable?":"Yes","Item Weight":"11 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => 'Black', 'col