            ['id' => 92, 'product_category_id' => 18, 'name' => '23.5\'\' Round Adjustable Height Glass Cocktail Table', 'slug' => '235-round-adjustable-height-glass-cocktail-table', 'sku' => 'ES-F5003', 'brand' => 'Fifth Function', 'price' => 151.79, 'stock' => 100, 'image' => 'images/products/235-round-adjustable-height-glass-cocktail-table/4864341ebac6.jpg', 'gallery' => '["images\\/products\\/235-round-adjustable-height-glass-cocktail-table\\/4864341ebac6.jpg","images\\/products\\/235-round-adjustable-height-glass-cocktail-table\\/4864341ebac6.jpg"]', 'description' => 'Choose your height from 33.5\'\' to 41\'\' using the adjustable lever on our versatile, round glass cocktail table.', 'features' => '["Choose your height from 33.5\'\' to 41\'\' using the adjustable lever on our versatile, round glass cocktail table.","This table is a great addition to any venue or party rental company inventory as it can be used for resting drinks or snacks as well as a display table for flowers or other decorative items.","The glass top with chrome base combination that is featured on the table gives it an elegant and contemporary appearance.","Other features include a protective base rin that prevents floors from scratching and a very easy to clean glass swivel top that can be used for a variety of events."]', 'specifications' => '{"Special Order Item":"No","Free Shipping Deal Type":"Free Shipping","Can ship FedEx?":"Yes","Brand":"Fifth Function","Shape":"Round","Commercial-Grade?":"Yes","Overall Length \\/ Depth":"23.5\'\' Dia.","Overall Height":"33.5\'\' - 41\'\' H","Overall Width":"23.5\'\'","Ships Assembled?":"No","Stackable?":"No","Item Weight":"29.00","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:11:22', 'updated_at' => '2026-06-18 08:38:17'],
