            ['id' => 127, 'product_category_id' => 17, 'name' => 'Kid\'s Folding Farm Table - 30\'\' x 72\'\' - Rustic - H-Legs', 'slug' => 'kids-folding-farm-table-30-x-72-rustic-h-legs', 'sku' => 'KFT26-RUST3072-H', 'brand' => 'Titan Event Furniture™', 'price' => 459.99, 'stock' => 100, 'image' => 'images/products/kids-folding-farm-table-30-x-72-rustic-h-legs/2dfc3faee380.jpg', 'gallery' => '["images\\/products\\/kids-folding-farm-table-30-x-72-rustic-h-legs\\/2dfc3faee380.jpg","images\\/products\\/kids-folding-farm-table-30-x-72-rustic-h-legs\\/6692a0435185.jpg","images\\/products\\/kids-folding-farm-table-30-x-72-rustic-h-legs\\/74214f9ddeb8.jpg","images\\/products\\/kids-folding-farm-table-30-x-72-rustic-h-legs\\/c38cbd604e42.jpg","images\\/products\\/kids-folding-farm-table-30-x-72-rustic-h-legs\\/20086d90c5bb.jpg","images\\/products\\/kids-folding-farm-table-30-x-72-rustic-h-legs\\/34e204e9980c.jpg","images\\/products\\/kids-folding-farm-table-30-x-72-rustic-h-legs\\/ab99ec9e089d.jpg"]', 'description' => 'Our 6\' x 30\'\' Kids Folding Farm Table is virtually the same as our popular 8\' x 40\'\' Solid Pine Folding Farm Table, but downsized so the kids at the party can also get in on the action.', 'features' => '["Our 6\' x 30\'\' Kids Folding Farm Table is virtually the same as our popular 8\' x 40\'\' Solid Pine Folding Farm Table, but downsized so the kids at the party can also get in on the action.","Shipping fully assembled, This children\'s folding farm table arrives with a smooth, beautiful pine top finish that gives way to sturdy, durable folding legs that seamlessly lock into place, supported by steel black folding bars and a pin.","Why add only one of these tables to your inventory?","Free shipping is included when you purchase 10+ or combine with a chair and table order over 2k!"]', 'specifications' => '{"Special Order Item":"No","UPC":"810171061713","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 10 or more","Can ship FedEx?":"No","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Color":"Polished Silver - Black engraved area","Material":"Pinewood","Shape":"Rectangle","Size":"6\' x 30\'\'","Commercial-Grade?":"Yes","Legs":"2.75\'\' Thick","Overall Length \\/ Depth":"72\'\'","Overall Height":"20.5\'\'","Overall Width":"30\'\'","Ships Assembled?":"Yes","Item Weight":"59 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:15:33', 'updated_at' => '2026-06-18 08:38:17'],
            ['id' => 128, 'product_category_id' => 17, 'name' => 'Sonoma Folding Farm Table Bench - 8\' x 12\'\' - Fruitwood with Black Grain', 'slug' => 'sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain', 'sku' => 'FT26-BENCH-BGFW1296', 'brand' => 'Titan Event Furniture™', 'price' => 190.99, 'stock' => 100, 'image' => 'images/products/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain/194c62643892.jpg', 'gallery' => '["images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/194c62643892.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/da06e00a688e.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/40dfcbd67bfd.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/8544a34891ac.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/59d6393b134c.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/7467c36b37ae.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/658998d5ba61.png"]', 'description' => 'Designed as the dedicated seating companion to the Sonoma Folding Farm Table, this 8-foot farm table bench seats 4 to 5 guests per side and folds flat for fast setup, breakdown, and compact storage.', 'features' => '["Designed as the dedicated seating companion to the Sonoma Folding Farm Table, this 8-foot farm table bench seats 4 to 5 guests per side and folds flat for fast setup, breakdown, and compact storage.","Purpose-built to match the Sonoma Farm Table in finish and proportion. Available in Rustic and Fruitwood with Black Grain to mirror the farm table colorways exactly, eliminating the mismatched look that comes from pairing benches and tables sourced separately.","Seats 4 to 5 guests per side across an 8-foot run. Two benches cover one Sonoma farm table for a full bench configuration of 8 to 10 guests, or mix with the Sonoma Cross Back Chair for a more varied seating arrangement without disrupting the aesthetic.","Folds flat for fast setup and compact storage. No tools, no assembly, no complexity \\u2014 the bench unfolds and is ready to use in seconds, and folds flat for efficient storage in a warehouse or trailer between events.","At 34 lbs., one person can move and set it efficiently. Light enough for a single crew member to handle across a full event setup, which matters when you\'re deploying multiple tables and benches against a tight load-in window.","Coordinates with cross back chairs for flexible seating arrangements. Pairs directly with the Sonoma Cross Back Chair for mixed bench-and-chair configurations at the same table, giving rental operators and venues flexibility to accommodate different guest preferences at the same setup."]', 'specifications' => '{"Special Order Item":"No","Can ship FedEx?":"Yes","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Overall Length \\/ Depth":"96\'\'","Overall Height":"17\'\'","Overall Width":"12\'\'","Ships Assembled?":"Yes","Item Weight":"34 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"How many people does this bench seat?","answer":"At 96\\" long and 12\\" wide, the bench comfortably seats 4 to 5 guests per side. Two benches per table covers a full 8-foot farm table setup for 8 to 10 guests."},{"question":"Does the bench fold for storage and transport?","answer":"Yes. The bench folds flat, reducing its footprint significantly for warehouse storage and trailer loading. No tools or assembly required \\u2014 unfold and it\'s ready to use."},{"question":"Can this bench be used outdoors?","answer":"Yes, for events on level outdoor surfaces. As with any wood-finish event furniture, storing the bench indoors between events and avoiding prolonged moisture exposure will extend its lifespan and preserve the finish over a rental or venue season."}]', 'default_color' => 'Fruitwood with Black Grain', 'color_variants' => '[{"label":"Fruitwood with Black Grain","swatch":"#47260c","gallery":["images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/59d6393b134c.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/7467c36b37ae.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/658998d5ba61.png","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/4e616e0e522e.png","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/031aac42ea7d.png"]},{"label":"Rustic","swatch":"images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/c67f5200b663.jpg","gallery":["images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/70947ad82581.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/836cd94f5564.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/9f9c48fdc097.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/51625d9d7d84.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/59d6393b134c.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/7467c36b37ae.jpg","images\\/products\\/sonoma-folding-farm-table-bench-8-x-12-fruitwood-with-black-grain\\/658998d5ba61.png"]}]', 'is_active' => 1, 'created_at' => '2026-06-18 08:15:45', 'updated_at' => '2026-06-18 08:38:17'],
