            ['id' => 130, 'product_category_id' => 4, 'name' => '300 Vinyl Padded Metal Folding Chairs and 4 Hanging Chair Carts Bundle', 'slug' => '300-vinyl-padded-metal-folding-chairs-and-4-hanging-chair-carts-bundle', 'sku' => 'MFCVP-BDL300', 'brand' => 'Titan Event Furniture™', 'price' => 10754.28, 'stock' => 100, 'image' => 'images/products/300-vinyl-padded-metal-folding-chairs-and-4-hanging-chair-carts-bundle/d16a361cf9a5.png', 'gallery' => '["images\\/products\\/300-vinyl-padded-metal-folding-chairs-and-4-hanging-chair-carts-bundle\\/d16a361cf9a5.png","images\\/products\\/300-vinyl-padded-metal-folding-chairs-and-4-hanging-chair-carts-bundle\\/d16a361cf9a5.png"]', 'description' => 'Move and store your metal folding chairs with ease when you purchase this money saving bundle that includes 300 Vinyl Padded Metal Folding Chairs and 4 Doubled Tiered Hanging Chair Carts.', 'features' => '["Move and store your metal folding chairs with ease when you purchase this money saving bundle that includes 300 Vinyl Padded Metal Folding Chairs and 4 Doubled Tiered Hanging Chair Carts.","Each Hanging Chair Cart can hold up to 84 Metal Folding Chairs and will fit through most standard doors and entryways with its 30.5\'\' width and 72\'\' total height.","There is some assembly required but it\'s relatively minor and should be easy enough for a single person to finish.","Our Titan Series Vinyl Padded Metal Folding Chairs feature a triple braced 18-gauge steel frame an quad hinges so you don\'t have to worry about its commercial-grade profile.","Available in multiple colors, the vinyl padded seat and backrest provide constant support and comfort with a 500 pound weight capacity and are a great choice for hotels, wedding venues, conference centers, or places of worship.","Each chair measures 30\'\' H, 18.5\'\' W and 19\'\' D and weighs only 12.5 lbs.","If you\'re looking to add steel folding chairs to your inventory and save some bucks along the way, you\'ll be hard-pressed to find a better deal than this bundle that always ships free."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping","Can ship FedEx?":"No","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Ships Assembled?":"No","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:15:51', 'updated_at' => '2026-06-18 08:38:17'],
