            ['id' => 139, 'product_category_id' => 4, 'name' => 'Premium Triple-Braced Steel Folding Chair - Beige', 'slug' => 'premium-triple-braced-steel-folding-chair-beige', 'sku' => 'MFC2BGE', 'brand' => 'Titan Event Furniture™', 'price' => 25.49, 'stock' => 100, 'image' => 'images/products/premium-triple-braced-steel-folding-chair-beige/fc4d7e119efb.jpg', 'gallery' => '["images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/fc4d7e119efb.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/90297af551dc.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/bab058418bb7.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/89c74d2b18b1.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/d7eaf1a7baf5.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/a71a2857858c.png","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/ae962817d2e2.jpg"]', 'description' => 'A commercial-grade metal folding chair built for schools, churches, convention centers, and party rental operations that need volume and durability at wholesale pricing.', 'features' => '["A commercial-grade metal folding chair built for schools, churches, convention centers, and party rental operations that need volume and durability at wholesale pricing.","An 18-gauge powder-coated steel frame with triple U-bracing, quad hinges, and a 500 lb. static weight capacity delivers the construction quality high-frequency use demands, at 11.5 lbs. per chair.","Commercial-grade chairs","Rugged 18 gauge steel frame","Powder-coated frame","Party Rental Tested!","Triple U-bracing and quad hinges prevent the flex and wear that fail lesser chairs. Three reinforcement points across the back frame and four-point hinge construction keep the TitanPRO\\u2122 structurally tight through thousands of setups, long after single-brace, dual-hinge alternatives start to wobble and loosen.","At 11.5 lbs., setup and breakdown move faster at scale. Lighter than most commercial metal folding chairs at this construction level, every pound saved per chair adds up quickly when your crew is moving 100, 200, or 500 chairs for a single event.","Powder-coated 18-gauge steel holds up through outdoor use and regular handling. Heavier gauge than consumer-grade alternatives and a rust-resistant powder-coat finish mean the frame maintains its appearance and structural integrity across years of commercial rental and venue use.","Non-marring floor glides protect finished floors at every event. Built-in floor glides on all four leg feet prevent scratching on hardwood, vinyl, polished concrete, and other finished surfaces, reducing floor repair costs over the life of your inventory.","Multiple color options match your facility or fleet without compromise. Available finishes let schools, churches, and rental operations deploy these chairs in a color that fits their space rather than defaulting to whatever is cheapest or most available."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Frame":"Steel","Folded Dimensions":"38\\u201d H x 18.5\\u201d W x 3.75\\u201d D","Overall Height":"29.75\'\'","Overall Width":"18.5\'\'","Overall Length \\/ Depth":"19\'\' D","Seat Size":"15.75\'\' x 15.75\'\'","Seat Type":"Solid","Ships Assembled?":"Yes","Has Arms":"No","Product Warranty":"3 Year Warranty","Item Weight":"11.5","Weight Capacity":"500 lbs.","Static Weight Capacity":"500 lbs.","Dynamic Weight Capacity":"300 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"How much weight can each chair hold?","answer":"All of our metal folding chairs are commercial-grade quality with a weight capacity of 500 pounds."},{"question":"Do the chairs ship assembled?","answer":"Yes, all of our Metal Folding Chairs ship assembled."},{"question":"Will these Chairs rust?","answer":"Our Metal Folding Chair frames are powder coated to insure that the frame will not rust."},{"question":"Are Metal Folding Chairs CA117 Rated?","answer":"Yes, our chairs are CA117 rated. For more information, please visit www.p65warnings.ca.gov."}]', 'default_color' => 'Beige', 'color_variants' => '[{"label":"Brown","swatch":"images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/16a6d1d71d23.png","gallery":["images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/70a8dc215818.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/b7de55305998.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/35df1ad2f5dc.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/0f6c454963f6.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/a71a2857858c.png","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/ae962817d2e2.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/4840dcb994ca.jpg"]},{"label":"Black","swatch":"images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/d889c95969e0.png","gallery":["images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/91d571602106.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/6eb428fc43e4.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/e6a8e838c7c7.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/73f7f04a45f8.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/276855974c08.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/3c15b5b8754c.jpg","images\\/products\\/premium-triple-braced-steel-folding-chair-beige\\/32b7cb083ffd.jpg"]},{"label":"Beige","swatch":"images\\/products\\/premium-triple-braced-ste