            ['id' => 149, 'product_category_id' => 26, 'name' => 'Monoblock Resin Chiavari Chair with Free Cushion - Champagne', 'slug' => 'monoblock-resin-chiavari-chair-with-free-cushion-champagne', 'sku' => 'RCC4CHP-MONO-V2', 'brand' => 'Titan Event Furniture™', 'price' => 53.49, 'stock' => 100, 'image' => 'images/products/monoblock-resin-chiavari-chair-with-free-cushion-champagne/4c85ad740448.jpg', 'gallery' => '["images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/4c85ad740448.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/d21f0d10250a.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/d1e462d40fbe.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/6ec77300723b.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/23d47ae19b89.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/af98df00b6ea.jpeg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/81dcf4994cc5.jpg"]', 'description' => 'A lightweight, single-piece monoblock resin chiavari chair built for wedding venues, event rental companies, and outdoor event operations that need the classic chiavari aesthetic at a lower per-chair cost and weight.', 'features' => '["A lightweight, single-piece monoblock resin chiavari chair built for wedding venues, event rental companies, and outdoor event operations that need the classic chiavari aesthetic at a lower per-chair cost and weight.","At 9 lbs. per chair with 1,100 lbs. of static weight capacity and a UV-treated resin finish that resists fading through outdoor seasons, it ships fully assembled, stacks for efficient storage, and includes a free cushion in your choice of wood-backed vinyl or soft 2\\" box styles.","Chairs are shipped assembled.","Made from high-grade Resin.","Glossy Painted Finish.","1 Piece molded chair (Monoblock)","Chairs are UV treated to prevent fading. (Perfect for outdoor and high humidity locations)","Stackable design for easy transportation and storage","Size: 36.5\\"H x 16\\"D x 16\\"W","Seat Height: 17.5\\"","Weight 9 lbs.","Single-piece monoblock construction eliminates every joint that can loosen or fail. No internal frame, no rungs, no connection points \\u2014 the chair is formed as one continuous piece of resin, so there is nothing to rattle, crack, or degrade structurally over years of commercial use.","At 9 lbs., large event setups move significantly faster. Noticeably lighter than frame-based resin chiavari chairs, the weight advantage compounds across high chair-count deployments where crew time and physical effort are real operational costs.","UV-treated finish holds color through outdoor seasons without fading. Suitable for garden ceremonies, outdoor receptions, and high-humidity environments, the resin finish resists the sun exposure and moisture that degrade lesser chairs over an event season.","Free cushion included in 10 style and color options. Choose from wood-backed vinyl in black, ivory, silver, or white, or soft 2\\" box cushions in black, brown, burlap, ivory, light gray, or white at checkout.","Lower per-chair cost makes scaling inventory more accessible. Monoblock construction reduces material and manufacturing cost versus frame-based alternatives, making it a practical entry point for operations building out a chiavari chair inventory or adding to an existing fleet."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"No","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Material":"Resin","Commercial-Grade?":"Yes","Overall Height":"36.5\\"","Overall Width":"16\\"","Overall Length \\/ Depth":"16\\"","Seat Color":"Gold","Seat Height":"17.5\\"","Seat Size":"16\\"D x 16\\"W","Ships Assembled?":"Yes","Stackable?":"Yes","Has Arms":"No","Product Warranty":"1 Years (chair)","Item Weight":"9 lbs.","Weight Capacity":"1100 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => 'Champagne', 'color_variants' => '[{"label":"Dark Brown","swatch":"images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/85bc6c140642.png","gallery":["images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/8868351e9c69.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/c2b46f1e5bce.jpeg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/96a754422ae1.jpeg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/cbd5324332c6.jpeg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/83078a743c6b.jpeg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/e72e756d0f2b.jpeg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/607a4fbc5709.jpeg"]},{"label":"Black","swatch":"images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/d889c95969e0.png","gallery":["images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/585dab05dacd.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/cee4b021a36d.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/bb2d3569939d.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/1bd8e3756c72.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/22d2d00a8c4f.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/53bd381b3d41.jpg","images\\/products\\/monoblock-resin-chiavari-chair-with-free-cushion-champagne\\/af98df00b6ea.jpeg"]},{"label":"Champagne","swatch":"images\\/products\\/monoblock-resin-chiavari-chair-