emium-steel-frame-mahogany\\/dfc8bb1129ee.jpg","images\\/products\\/resin-chiavari-chair-with-free-cushion-premium-steel-frame-mahogany\\/c5c3ccdde3cf.jpg","images\\/products\\/resin-chiavari-chair-with-free-cushion-premium-steel-frame-mahogany\\/4721891b9e4e.jpg","images\\/products\\/resin-chiavari-chair-with-free-cushion-premium-steel-frame-mahogany\\/82bae68d0c4d.jpg","images\\/products\\/resin-chiavari-chair-with-free-cushion-premium-steel-frame-mahogany\\/948a833fb379.png","images\\/products\\/resin-chiavari-chair-with-free-cushion-premium-steel-frame-mahogany\\/ba62208e5a76.jpg"]}]', 'is_active' => 1, 'created_at' => '2026-06-18 08:25:24', 'updated_at' => '2026-06-18 08:38:17'],
            ['id' => 158, 'product_category_id' => 6, 'name' => '100 Person Outdoor Wedding Bundle - 100 Resin Folding Chairs, 12 Banquet Tables', 'slug' => '100-person-outdoor-wedding-bundle-100-resin-folding-chairs-12-banquet-tables', 'sku' => 'ES105BDL', 'brand' => 'Titan Event Furniture™', 'price' => 5037.12, 'stock' => 100, 'image' => 'images/products/100-person-outdoor-wedding-bundle-100-resin-folding-chairs-12-banquet-tables/88f8506cd27f.jpg', 'gallery' => '["images\\/products\\/100-person-outdoor-wedding-bundle-100-resin-folding-chairs-12-banquet-tables\\/88f8506cd27f.jpg","images\\/products\\/100-person-outdoor-wedding-bundle-100-resin-folding-chairs-12-banquet-tables\\/88f8506cd27f.jpg"]', 'description' => 'Create a stunning outdoor wedding with our 100 Person Bundle, featuring 100 Resin Folding Chairs and 12 Banquet Tables.', 'features' => '["Create a stunning outdoor wedding with our 100 Person Bundle, featuring 100 Resin Folding Chairs and 12 Banquet Tables.","This elegant and durable set ensures a beautiful and seamless event setup.","Buy all of your outdoor wedding equipment with one purchase!","This product bundle includes 100 of our Commercial Grade resin folding chairs as well as your choice of 12 folding tables.","Choose the chair color: white, black, or mahogany.","Then, choose what table works best for you: 8\'x30\\" plastic or wood folding banquet tables, or 60\\" round wood or plastic folding tables.","You cannot combine round and banquet folding tables."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping, Free Shipping on Tables and Chairs Over $5k","Can ship FedEx?":"Yes","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"No","Ships Assembled?":"No","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:25:25', 'updated_at' => '2026-06-18 08:38:17'],
            ['id' => 159, 'product_category_id' => 6, 'name' => '100 Resin Folding Chairs Bundle', 'slug' => '100-resin-folding-chairs-bundle', 'sku' => 'RFC6100-BDL', 'brand' => 'Titan Event Furniture™', 'price' => 3399, 'stock' => 100, 'image' => 'images/products/100-resin-folding-chairs-bundle/678472f0a2e9.jpg', 'gallery' => '["images\\/products\\/100-resin-folding-chairs-bundle\\/678472f0a2e9.jpg","images\\/products\\/100-resin-folding-chairs-bundle\\/8d1e59e92bd2.jpg","images\\/products\\/100-resin-folding-chairs-bundle\\/64eae627846e.jpg","images\\/products\\/100-resin-folding-chairs-bundle\\/ce0c0c083be5.jpg","images\\/products\\/100-resin-folding-chairs-bundle\\/032f7779b75b.jpg","images\\/products\\/100-resin-folding-chairs-bundle\\/9fe4e12618a3.jpg"]', 'description' => 'Elevate your event with our TitanPRO™ Resin Folding Chairs.', 'features' => '["Elevate your event with our TitanPRO\\u2122 Resin Folding Chairs.","This 100-pack of wedding chairs is designed for style and durability, these chairs are perfect for weddings, parties, and conferences, providing comfort and elegance.","This product bundle features a pack of 100 of our popular Resin Folding Chairs.","Our wholesale resin folding chairs are a perfect fit for almost any application.","Perhaps the most popular padded wedding chair, they have become the standard for garden folding chairs, as they are made to look identical to traditional wood folding chairs.","Same weight and dimensions, but these chairs are stronger than any wood chair and will last through years of tough use.","The 100-Pack featured here is a great for anyone looking to replenish their event furniture inventory or striving for a big splash with their their first jump into the party rental industry.","Weddings, graduations, concerts, banquet facilities - you really can\'t go wrong by choosing any of our Resin Folding Chairs."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping","Can ship FedEx?":"No","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Ships Assembled?":"Yes","Stackable?":"Yes","Has Arms":"No","Weight Capacity":"1000 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"Can I add more chairs to the bundle and get a discount on those chairs?","answer":"Yes, you can add more chairs and qualify for the bundle discount. We recommend reaching out and asking for a quote!"},{"question":"Do bundles take longer to ship than individual items?","answer":"No, all our products have the same ETA as long as they\\u2019re in stock!"},{"question":"Can I get a mix of colored chairs within a bundle?","answer":"Yes, while this option is not available directly on our website, our sales team would be happy to assist you. Please contact one of our representatives, and we can create a custom bundle tailored to your needs."}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:25:29', 'updated_at' => '2026-06-18 08:38:17'],
            ['id' => 160, 'product_category_id' => 6, 'name' => '100 Resin Folding Chairs with 4 Dollies and 4 Straps Bundle', 'slug' => '100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle', 'sku' => 'ES113BDL', 'brand' => 'Titan Event Furniture™', 'price' => 3852.36, 'stock' => 100, 'image' => 'images/products/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle/44112126cc19.jpg', 'gallery' => '["images\\/products\\/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle\\/44112126cc19.jpg","images\\/products\\/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle\\/244686dc2ac0.jpg","images\\/products\\/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle\\/c3918b5f55d9.jpg","images\\/products\\/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle\\/4ccfac6e743d.jpg","images\\/products\\/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle\\/5ce0bb0f4f9e.png","images\\/products\\/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle\\/16b2c68807db.jpeg","images\\/products\\/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle\\/49ebd6b50ec4.jpg","images\\/products\\/100-resin-folding-chairs-with-4-dollies-and-4-straps-bundle\\/b719f6d3ae17.jpeg"]', 'description' => 'Event ready package featuring 100 TitanPRO Resin Folding Chairs, 4 folding chair dollies and 4 straps to extra security.', 'features' => '["Event ready package featuring 100 TitanPRO Resin Folding Chairs, 4 folding chair dollies and 4 straps to extra security.","Perfect solution for easy transport and storage of your wedding chairs.","This bundle includes 100 resin folding chairs with 4 dollies and 4 straps.","Generally resin folding chairs are stacked 25 chairs high on a dolly, so this package includes the dollies and straps you need to securely store and transport your 100 chairs.","TitanPRO\\u2122 Resin Folding ChairWhen you buy our TitanPRO\\u2122 Resin Folding Chairs in bulk, not only are you get getting free shipping, you\'re getting commercial-grade quality, premier wedding chairs at a wholesale price.","Each chair looks identical to traditonal wood folding chairs but with new age performance.","The resin material is 100% virgin polypropylene with UV protectants and carries a robust weight capacity of 1000 lbs. while only weighing 10.5 pounds itself.","These Resin Folding Chairs have a built in nesting design that allows them to stack neatly and securely as high as 25 on a dolly like the one in this bundle or as high are you\'re comfortably with on the floor.","Lightweight, easy to move and even easier to clean, if you\'re looking for a folding wedding chair package, look no further than our TitanPRO\\u2122 Resin Folding Chairs that perform long after the party is over.","Folding Chair DollyIf you\'re looking to preserve floor space while also making the set up and break down of events a little easier then you absolutely need a Folding Chair Dolly.","After a few minutes assembling the dolly, the 2 fixed wheels and 2 swivel wheels will have you and your employees moving in and out of tight spots like a young Jacques Cousteau manoeuvering through the Mediterranean.","While the 40 lb.","Folding Chair Dolly can carry up to 600 lbs. what makes it a dream to match in this bundle is the ability to carry 25 Resin Folding Chairs each without adding any additional floor space that will be taken up.","At only 44\'\' long and 19\'\' wide, that\'s about the only space that\'ll be taken up on the floor, even with Resin Folding Chairs stacked on top!How Much Space Do You Need?If you can fit a typical sofa in your warehouse or storage space, you\'ll have no problem keeping your dollies and chairs locked and loaded for your next event!"]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping, Free Shipping on 50 or more","Can ship FedEx?":"No","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Ships Assembled?":"Yes","Stackable?":"Yes","Weight Capacity":"1000 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"Can I add more chairs to the bundle and get a discount on those chairs?","answer":"Yes, you can add more chairs and qualify for the bundle discount. We recommend reaching out and asking for a quote!"},{"question":"Do bundles take longer to ship than individual items?","answer":"No, all our products have the same ETA as long as they\\u2019re in stock!"},{"question":"Can I get a mix of colored chairs within a bundle?","answer":"Yes, while this option is not available directly on our website, our sales team would be happy to assist you. Please contact one of our representatives, and we can create a custom bundle tailored to your needs."},{"question":"What are Resin Folding Chairs made of?","answer":"Our Resin folding chairs are made from high-density polypropylene, which are durable, lightweight plastics that are resistant to weather, stains, and scratches."}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:25:35', 'updated_at' => '2026-06-18 08:38:17'],
            ['id' => 161, 'product_category_id' => 6, 'name' => '100 Slatted Resin Folding Chairs Bundle', 'slug' => '100-slatted-resin-folding-chairs-bundle', 'sku' => 'RFCSL6WH-100BDL', 'brand' => 'Titan Event Furniture™', 'price' => 3349, 'stock' => 100, 'image' => 'images/products/100-slatted-resin-folding-chairs-bundle/47c744cbfa14.jpg', 'gallery' => '["images\\/products\\/100-slatted-resin-folding-chairs-bundle\\/47c744cbfa14.jpg","images\\/products\\/100-slatted-resin-folding-chairs-bundle\\/21fa3c6d53ee.jpg","images\\/products\\/100-slatted-resin-folding-chairs-bundle\\/9e2efee26889.jpg","images\\/products\\/100-slatted-resin-folding-chairs-bundle\\/c8930a415031.jpg","images\\/products\\/100-slatted-resin-folding-chairs-bundle\\/34b1e245fa17.jpg"]', 'description' => 'This product bundle features a pack of 100 of our popular White Resin Folding Chairs with slatted seat.', 'features' => '["This product bundle features a pack of 100 of our popular White Resin Folding Chairs with slatted seat.","Our wholesale resin folding chairs are a perfect fit for almost any application.","One of the more popular wedding chairs, they have become the standard for garden folding chairs, as they are made to look identical to traditional wood folding chairs.","Maintenance is easy and if the slatted seat isn\'t for a particular customer or event, this chair has clips on the back to add a padded cushion!","The 100-Pack featured here is a great for anyone looking to replenish their event furniture inventory or striving for a big splash with their their first jump into the party rental industry.","Weddings, graduations, concerts, or any banquet facility would be wise to invest our Slatted Seat White Resin Folding Chairs!"]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping, Free Shipping on Tables and Chairs Over $5k","Can ship FedEx?":"No","Brand":"Titan Event Furniture\\u2122","Material":"Resin","Commercial-Grade?":"Yes","Ships Assembled?":"Yes","Stackable?":"Yes","Has Arms":"No","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:25:38', 'updated_at' => '2026-06-18 08:38:17'],
            ['id' => 162, 'product_category_id' => 6, 'name' => '200 Resin Folding Chairs with 8 Dollies and 8 straps bundle', 'slug' => '200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle', 'sku' => 'ES114BDL', 'brand' => 'Titan Event Furniture™', 'price' => 7512.72, 'stock' => 100, 'image' => 'images/products/200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle/ef1984c8a5e7.jpg', 'gallery' => '["images\\/products\\/200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle\\/ef1984c8a5e7.jpg","images\\/products\\/200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle\\/854b5f47d675.jpg","images\\/products\\/200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle\\/de7f65d3b876.jpg","images\\/products\\/200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle\\/d549395c8c95.jpg","images\\/products\\/200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle\\/b16e69a44778.png","images\\/products\\/200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle\\/81613e309589.jpeg","images\\/products\\/200-resin-folding-chairs-with-8-dollies-and-8-straps-bundle\\/1ed4380e947c.jpg"]', 'description' => 'Event ready package featuring 200 TitanPRO Resin Folding Chairs, 8 folding chair dollies and 8 straps to extra security.', 'features' => '["Event ready package featuring 200 TitanPRO Resin Folding Chairs, 8 folding chair dollies and 8 straps to extra security.","Perfect solution for easy transport and storage of your wedding chairs.","This bundle includes 200 resin folding chairs with 8 dollies and 8 straps.","You have the option of adding stack covers for each stack of chairs, to protect from dust.","This is a great bundle package for event venues that host a lot of weddings, as with 200 chairs you have everything you need for a large event, including a way to safely and efficiently store and transport your chairs to and from the ceremony and event site.","TitanPRO\\u2122 Resin Folding ChairWhen you buy our TitanPRO\\u2122 Resin Folding Chairs in bulk, not only are you get getting free shipping, you\'re getting commercial-grade quality, premier wedding chairs at a wholesale price.","Each chair looks identical to traditonal wood folding chairs but with new age performance.","The resin material is 100% virgin polypropylene with UV protectants and carries a robust weight capacity of 1000 lbs. while only weighing 10.5 pounds itself.","These Resin Folding Chairs have a built in nesting design that allows them to stack neatly and securely as high as 25 on a dolly like the one in this bundle or as high are you\'re comfortably with on the floor.","Lightweight, easy to move and even easier to clean, if you\'re looking for a folding wedding chair package, look no further than our TitanPRO\\u2122 Resin Folding Chairs that perform long after the party is over.","Folding Chair DollyIf you\'re looking to preserve floor space while also making the set up and break down of events a little easier then you absolutely need a Folding Chair Dolly.","After a few minutes assembling the dolly, the 2 fixed wheels and 2 swivel wheels will have you and your employees moving in and out of tight spots like a young Jacques Cousteau manoeuvering through the Mediterranean.","While the 40 lb.","Folding Chair Dolly can carry up to 600 lbs. what makes it a dream to match in this bundle is the ability to carry 25 Resin Folding Chairs each without adding any additional floor space that will be taken up.","At only 44\'\' long and 19\'\' wide, that\'s about the only space that\'ll be taken up on the floor, even with Resin Folding Chairs stacked on top!How Much Space Will You Need?Just because this bundle takes up the same square footage as a hot tub doesn\'t mean you have to throw away your dreams of an eternal spa week.","You can have both, although this bundle is probably way more beneficial to your event or party rental business(and it ships free)!"]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping, Free Shipping on 50 or more","Can ship FedEx?":"No","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"No","Ships Assembled?":"No","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"Can I add more chairs to the bundle and get a discount on those chairs?","answer":"Yes, you can add more chairs and qualify for the bundle discount. We recommend reaching out and asking for a quote!"},{"question":"Do bundles take longer to ship than individual items?","answer":"No, all our products have the same ETA as long as they\\u2019re in stock!"},{"question":"Can I get a mix of colored chairs within a bundle?","answer":"Yes, while this option is not available directly on our website, our sales team would be happy to assist you. Please contact one of our representatives, and we can create a custom bundle tailored to your needs."}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:25:44', 'updated_at' => '2026-06-18 08:38:17'],
