            ['id' => 171, 'product_category_id' => 6, 'name' => 'Replacement Resin Folding Chair Bolt Covers - Pack of 100', 'slug' => 'replacement-resin-folding-chair-bolt-covers-pack-of-100', 'sku' => 'RFCSC6BDL', 'brand' => 'Titan Event Furniture™', 'price' => 49, 'stock' => 100, 'image' => 'images/products/replacement-resin-folding-chair-bolt-covers-pack-of-100/bd4fe1e3e11b.jpg', 'gallery' => '["images\\/products\\/replacement-resin-folding-chair-bolt-covers-pack-of-100\\/bd4fe1e3e11b.jpg","images\\/products\\/replacement-resin-folding-chair-bolt-covers-pack-of-100\\/75f777e13a21.png","images\\/products\\/replacement-resin-folding-chair-bolt-covers-pack-of-100\\/bd0f591f7dcc.png","images\\/products\\/replacement-resin-folding-chair-bolt-covers-pack-of-100\\/ac0773ae2730.png"]', 'description' => 'Pack of 100 Replacement Resin Folding Chair Bolt Covers, also known as "screw caps".', 'features' => '["Pack of 100 Replacement Resin Folding Chair Bolt Covers, also known as \\"screw caps\\".","Available in Black, White, Dark Brown and Mahogany.WhiteDark BrownBlackMahogany"]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping","Can ship FedEx?":"Yes","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"Yes","Ships Assembled?":"No","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:27:23', 'updated_at' => '2026-06-18 11:38:01'],
            ['id' => 172, 'product_category_id' => 6, 'name' => 'Dark Brown Resin Folding Chair with Ivory Pad', 'slug' => 'dark-brown-resin-folding-chair-with-ivory-pad', 'sku' => 'RFC6DBRIV', 'brand' => 'Titan Event Furniture™', 'price' => 32.99, 'stock' => 100, 'image' => 'images/products/dark-brown-resin-folding-chair-with-ivory-pad/cb6af739586b.jpg', 'gallery' => '["images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/cb6af739586b.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/caf36e7f437e.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/a9a946fba05e.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/2b1a819605d3.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/5a74998050b4.jpeg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/fb716ecaa594.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/dcfe5d365775.jpg"]', 'description' => 'Resin Folding Chairs are the ideal choice for padded wedding chairs and the standard for garden folding chairs.', 'features' => '["Resin Folding Chairs are the ideal choice for padded wedding chairs and the standard for garden folding chairs.","UV protected. lightweight and easy to maintain.","Suitable for indoor and outdoor use.","Our wholesale resin folding chairs are a perfect fit for almost any application.","Perhaps the most popular padded wedding chair, they have become the standard for garden folding chairs, as they are made to look identical to traditional wood folding chairs.","Same weight and dimensions, but these chairs are stronger than any wood chair and will last through years of tough use.","The resin material is 100% virgin polypropylene with UV protectants included in the molding process.","This ensures the chairs will not fade or lose their bright appearance over time.","These chairs are incredibly easy to clean and maintain, as they can be wiped off with a damp rag in between rentals or events.","Resin folding chairs can be used indoors or outdoors in an any weather without fear of moisture issues.","Simply a beautiful chair, the aesthetics are enhanced with color-matching bolt covers.","Replacement covers available.","Event setups are quick and easy with resin folding chairs.","Each chair weighs only 10.5 lbs, so several can be carried at one time.","Unfold the seat and notice that the locking seat snaps into place for the stability and safety of your clients or guests.","These chairs feature a removable \\u00bd\\u2019\\u2019 vinyl padded seat cushion which is comfortable and supported by the seat frame and seat bar.","Further easing ownership over the life of the chairs, the cushion can be removed for repair.","Don\\u2019t want to repair your cushions?","No worries - we\\u2019ve got you covered on replacements as well: replacement cushions.","Resin folding chairs have a built-in nesting design that allow the chairs to stack amazingly straight up and down.","Adding to that, the chairs resist sliding off one another making moving them around a breeze.","Generally our customers will make stacks 25 high.","25 is an easy number for counting and makes for a very manageable stack for transport, whether on a cart or dolly.","However, for storage, these chairs can be stacked as high as you are comfortable with.","We know that weight capacity is important to our commercial customers.","Our chairs have been independently certified by SGS Laboratories to hold in excess of 1000 lbs.","The chairs and cushions have also been tested and found to meet the requirements of CA TB 133 (stricter than CA117).","These chairs have been party rental proven in our very own event rental company to be tough, durable, reliable, easy to transport, a great investment and popular with our clients.","Check out our buyer\'s guide for 10 reasons to choose resin folding chairs or our Ultimate Folding Chairs Buyer\'s Guide for more information."]', 'specifications' => '{"Special Order Item":"No","Dimensions":"Height: 31\\" Width: 17.5\\" Seat Width: 15.5\\" Seat Depth: 14\\" Seat Height: 17.5\\" Folded Length: 35\\" Folded Thickness: 2.25\\" Weight: 10 lbs","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Material":"Resin","Commercial-Grade?":"Yes","Folded Dimensions":"17.5\'\' x 35\'\' x 2.19\'\'","Padded Seat":"Yes","Overall Height":"31\'\'","Overall Width":"17.5\'\'","Overall Length \\/ Depth":"20\'\'","Footprint":"17.5\'\' x 20\'\'","Seat Height":"17.5\'\'","Seat Size":"15.5\'\' x 14\'\'","Ships Assembled?":"Yes","Stackable?":"Yes","Has Arms":"No","Product Warranty":"3 Year Warranty","Static Weight Capacity":"1102 lbs.","Dynamic Weight Capacity":"353 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"What is the weight capacity of Resin Folding Chairs?","answer":"These chairs have been independently tested by SGS laboratories to hold in excess of 1000+ lbs static weight."},{"question":"Can I stack Resin Folding Chairs?","answer":"Yes, our customers typically stack resin folding chairs 25 high. Check out our Folding Chair Dolly so you can better move them from Point A to B."},{"question":"Is the cushion removable?","answer":"Yes, we sell replacement cushions. Please visit Replacement Cushion for Resin Folding Chairs."},{"question":"What are Resin Folding Chairs made of?","answer":"Our Resin folding chairs are made from high-density polypropylene, which are durable, lightweight plastics that are resistant to weather, stains, and scratches."},{"question":"Are Resin Folding Chairs suitable for outdoor use?","answer":"Yes, our Resin Folding Chairs are designed to withstand outdoor conditions. They are resistant to UV rays, moisture, and temperature changes, making them ideal for events, weddings, and outdoor gatherings."},{"question":"How do I clean Resin Folding Chairs?","answer":"To clean Resin Folding Chairs, wipe them down with a mild soap and water solution. For tougher stains, use a soft brush. Rinse thoroughly and let them air dry."}]', 'default_color' => 'Dark Brown w/ Ivory Pad', 'color_variants' => '[{"label":"Brown w\\/ Ivory Pad","swatch":"#85522b","gallery":["images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/8dcf8114178f.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/a0d6af5c3962.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/ba21e763c863.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/b6ac51a41789.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/5e22d88271fd.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/82e03ff5a9b0.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/1f9e50da51b0.jpeg"]},{"label":"Dark Brown w\\/ Ivory Pad","swatch":"#361d0a","gallery":["images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/cb6af739586b.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/caf36e7f437e.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/a9a946fba05e.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/2b1a819605d3.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/5a74998050b4.jpeg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/fb716ecaa594.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/dcfe5d365775.jpg"]},{"label":"Black","swatch":"images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/d889c95969e0.png","gallery":["images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/077ee8391465.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-pad\\/fddeca19b4cf.jpg","images\\/products\\/dark-brown-resin-folding-chair-with-ivory-