            ['id' => 184, 'product_category_id' => 30, 'name' => 'King Wingback Throne Chair - White Vinyl/Gold Frame', 'slug' => 'king-wingback-throne-chair-white-vinylgold-frame', 'sku' => 'KWBTHRONE58GLDWH', 'brand' => 'Crowne', 'price' => 991.99, 'stock' => 100, 'image' => 'images/products/king-wingback-throne-chair-white-vinylgold-frame/5caf1d090530.jpg', 'gallery' => '["images\\/products\\/king-wingback-throne-chair-white-vinylgold-frame\\/5caf1d090530.jpg","images\\/products\\/king-wingback-throne-chair-white-vinylgold-frame\\/cafe051484b3.jpg","images\\/products\\/king-wingback-throne-chair-white-vinylgold-frame\\/6ab69a92521f.jpg","images\\/products\\/king-wingback-throne-chair-white-vinylgold-frame\\/a79cc3bfad0b.jpg","images\\/products\\/king-wingback-throne-chair-white-vinylgold-frame\\/22b595fccf2e.jpg","images\\/products\\/king-wingback-throne-chair-white-vinylgold-frame\\/d7f68b3f712d.jpg"]', 'description' => 'Great Odin\'s Raven!', 'features' => '["Great Odin\'s Raven!","Fly to the front of the line with our new King Wingback Throne Chair.","Fit for the king or queen of the party, this majestic throne chair captivates with every detail, from the angelic wings gracing its high, elegantly contoured back to the fierce lion heads guarding each armrest.","Built from a solid wood frame, it combines strength with elegance, ensuring durability even under the demands of grand events.","The plush, vinyl upholstery envelops the seat and backrest, offering supreme comfort while accentuating its lavish appeal.","Intricate carvings adorn the chair\\u2019s arms and legs, adding an extra layer of grandeur.","Whether for weddings, VIP lounges, or photo booths, this throne commands attention, transforming any event space into a setting fit for royalty."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"Crowne","Color":"Gold","Material":"Wood","Commercial-Grade?":"Yes","Overall Height":"72\'\'","Overall Width":"36\'\'","Overall Length \\/ Depth":"35\'\'","Ships Assembled?":"Yes","Has Arms":"No","Item Weight":"65 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:29:48', 'updated_at' => '2026-06-18 08:38:17'],
