            ['id' => 193, 'product_category_id' => 30, 'name' => 'Royal Heart Throne Chair - Red Vinyl/Gold Frame', 'slug' => 'royal-heart-throne-chair-red-vinylgold-frame', 'sku' => 'RHTHRONE58GLDRD', 'brand' => 'Crowne', 'price' => 945.99, 'stock' => 100, 'image' => 'images/products/royal-heart-throne-chair-red-vinylgold-frame/fe4acf0e1785.jpg', 'gallery' => '["images\\/products\\/royal-heart-throne-chair-red-vinylgold-frame\\/fe4acf0e1785.jpg","images\\/products\\/royal-heart-throne-chair-red-vinylgold-frame\\/121073e68bfb.jpg","images\\/products\\/royal-heart-throne-chair-red-vinylgold-frame\\/ca5a864e9f6a.jpg"]', 'description' => 'You don’t have to be the ruler of Wonderland, Ann Wilson, or Bret ‘The Hitman’ Hart to sit on this throne designed for esteemed members of the Heart Dynasty—but you’ll sure feel like it.', 'features' => '["You don\\u2019t have to be the ruler of Wonderland, Ann Wilson, or Bret \\u2018The Hitman\\u2019 Hart to sit on this throne designed for esteemed members of the Heart Dynasty\\u2014but you\\u2019ll sure feel like it.","Each Royal Heart Throne Chair features a hand-carved, solid wood frame, showcasing intricate craftsmanship that makes every detail a true work of art.","Built from durable, commercial-grade materials, the frame not only ensures longevity but also adds classic elegance to any event decor.","Paired with plush, high-quality vinyl cushions, these throne chairs deliver both regal comfort and timeless appeal.","Perfect for weddings, VIP gatherings, galas, and Quincea\\u00f1eras, this throne chair is handcrafted to make any occasion extraordinary, combining royal charm with exceptional strength and artistry.","And because the boss once sang \\"two hearts are better than one\\", these throne chairs ship free when you combine them with any purchase over $5k!"]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k","Can ship FedEx?":"No","Country of Manufacture":"China","Brand":"Crowne","Color":"Red","Material":"Wood","Commercial-Grade?":"Yes","Overall Height":"68\'\'","Overall Width":"31\'\'","Overall Length \\/ Depth":"49\'\'","Ships Assembled?":"No","Has Arms":"No","Weight Capacity":"453 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 08:30:36', 'updated_at' => '2026-06-18 08:38:17'],
