            ['id' => 207, 'product_category_id' => 3, 'name' => '200 Wood Folding Chairs with 8 Dollies and 8 Straps Bundle', 'slug' => '200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle', 'sku' => 'ES120XBDL', 'brand' => 'Titan Event Furniture™', 'price' => 8472.72, 'stock' => 100, 'image' => 'images/products/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle/5001907de05e.jpg', 'gallery' => '["images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/5001907de05e.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/3c8c438387c4.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/5bd55cd94798.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/109a79aecddd.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/9fb4d6234125.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/78aba890942e.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/d49578e064f6.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/2081463e8c15.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/b620ed869082.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/021308b52e68.jpg","images\\/products\\/200-wood-folding-chairs-with-8-dollies-and-8-straps-bundle\\/60a5b1dbf638.jpg"]', 'description' => 'Upgrade your event setup with our bundle of 200 Wood Folding Chairs, complete with 8 Dollies and 8 Straps for easy transport.', 'features' => '["Upgrade your event setup with our bundle of 200 Wood Folding Chairs, complete with 8 Dollies and 8 Straps for easy transport.","Perfect for weddings, parties, and gatherings, these elegant chairs offer both style and convenience.","Our dollar saving bundle deal includes 200 Wood Folding Chairs with 8 dollies and 8 straps to securely transport your chairs to and from any event venue.","Also included in this bundle is an option to purchase stack covers for added protection and worry free storage.","Please note: the Mahogany Wood Folding Chairs feature a black pad.","If you\'re an event venue or party rental company owner and you have 50 square feet free in your warehouse or storage facility, we suggest investing in our 200 Wood Folding Chair and 8 Folding Chair Dolly bundle.","If you still have 50 square after that then by all means, buy that hot tub you\'ve been craving and get ready for an eternal summer."]', 'specifications' => '{"Free Shipping Deal Type":"Free Shipping","Can ship FedEx?":"No","Brand":"Titan Event Furniture\\u2122","Commercial-Grade?":"No","Ships Assembled?":"No","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"Can I add more chairs to the bundle and get a discount on those chairs?","answer":"Yes, you can add more chairs and qualify for the bundle discount. We recommend reaching out and asking for a quote!"}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 10:16:21', 'updated_at' => '2026-06-18 10:16:21'],
            ['id' => 208, 'product_category_id' => 3, 'name' => 'Wood Folding Chair - Black - Closeout', 'slug' => 'wood-folding-chair-black-closeout', 'sku' => 'WFC5BK', 'brand' => 'Titan Event Furniture™', 'price' => 37.99, 'stock' => 100, 'image' => 'images/products/wood-folding-chair-black-closeout/87b996efa06c.jpg', 'gallery' => '["images\\/products\\/wood-folding-chair-black-closeout\\/87b996efa06c.jpg","images\\/products\\/wood-folding-chair-black-closeout\\/6fae96fc3c4c.jpg","images\\/products\\/wood-folding-chair-black-closeout\\/8bb330ccae27.jpg","images\\/products\\/wood-folding-chair-black-closeout\\/57386602cfd1.jpg","images\\/products\\/wood-folding-chair-black-closeout\\/a1b64f5b1a37.jpg","images\\/products\\/wood-folding-chair-black-closeout\\/263c7399f659.jpg","images\\/products\\/wood-folding-chair-black-closeout\\/044d9163ea1a.jpg"]', 'description' => 'Our Flagship, commercial-grade Wood Folding Chairs made from heavy-duty beechwood.', 'features' => '["Our Flagship, commercial-grade Wood Folding Chairs made from heavy-duty beechwood.","Timeless appeal.","Padded vinyl seat. lightweight design allows for easy storage and transportation.","When you need padded wedding chairs, wood folding chairs for events are a classic choice.","Our wood folding chairs have been party rental proven to withstand the rigors of everyday use.","They\'re commercial-grade with heavy duty beechwood construction and a padded vinyl seat.","Wood folding chairs are easy to transport, store and set up due to their lightweight design and stackability when folded.","Our wholesale wood folding chairs are primed and painted with multiple coats for a durable finish that is simple to maintain for years to come.","To get even more in depth on why wood folding chairs are a great choice, take a look at our product spotlight on Natural Wood Folding ChairsWhen you need padded wedding chairs, wood folding chairs for events are a classic choice.","Our wooden folding chairs have been party rental proven to withstand the rigors of everyday use.","Use them indoors or outside, for a formal wedding or backyard party, these chairs are as dynamic as they are tough.","The commercial-grade, heavy duty constructed beechwood frame gives way to a plush vinyl padded seat that supports and provides long lasting comfort for your guests.","This timeless industry classic seating options is easy to transport on a dolly, store and set up due to the lightweight design and stackability when folded.","To get even more in depth on why wood folding chairs are a great choice, take a look at our product spotlight on Natural Wood Folding Chairs"]', 'specifications' => '{"Special Order Item":"No","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Material":"Beechwood","Commercial-Grade?":"Yes","Frame":"7\\/8\'\'x2\'\' Beechwood","Folded Dimensions":"17.5\'\'H x 2.5\'\'D x 35.5\'\'L","Padded Seat":"Yes","Overall Height":"30.5\'\'","Overall Width":"17.5\'\'","Overall Length \\/ Depth":"19\'\'","Seat Height":"17.5\'\'","Seat Material":"Vinyl","Seat Size":"15.5\'\'W x 14.5\'\'D","Ships Assembled?":"Yes","Has Arms":"No","Product Warranty":"1 year","Item Weight":"12 lbs.","Weight Capacity":"300 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"How much do Wood Folding Chairs weigh?","answer":"All of our Titan Series Wood Folding Chairs weight 12 lbs."},{"question":"How High Can I Stack Wood Folding Chairs?","answer":"We recommend stacking 25 high on a Folding Chair Dolly or as high as you\'re comfortable with on the floor in a secure location."},{"question":"Can I use Wood Folding Chairs outside?","answer":"Yes, these chairs are suitable for indoor and outdoor use, but we recommend storing them in a climate controlled space."},{"question":"Do these chairs have a protective coating on them?","ans