            ['id' => 210, 'product_category_id' => 3, 'name' => 'French Bistro Slatted Cafe Folding Chair', 'slug' => 'french-bistro-slatted-cafe-folding-chair', 'sku' => 'BISTRO48CHAIR', 'brand' => 'Titan Event Furniture™', 'price' => 31.99, 'stock' => 100, 'image' => 'images/products/french-bistro-slatted-cafe-folding-chair/322817a27141.png', 'gallery' => '["images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/322817a27141.png","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/ba79516b6c96.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/00e7f4688707.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/9dd69f96a957.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/d4a76ffd0804.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/abcffcab29cf.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/f79208a2c47a.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/0f17f82b83ad.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/9c631f6c3be2.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/a230919fff80.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/36a18a77cea6.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/1e3efd9f06fb.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/9c68137cb737.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/acb8a235d517.jpg","images\\/products\\/french-bistro-slatted-cafe-folding-chair\\/58d861e6af54.jpg"]', 'description' => 'Give your gatherings a European feel with French Cafe Bistro Folding chairs.', 'features' => '["Give your gatherings a European feel with French Cafe Bistro Folding chairs.","The hardwood slats and iron-finish metal frame add garden elegance to special events, with a nod to open spaces on cobblestone streets.","The Eco-friendly, stable and strong Acacia wood slats that make up the back and seat of our French Bistro Folding Chair are carefully stained to give an aesthetically pleasing appearance that gives way to an aesthetically welcoming shape on this unique folding chair.","Each chair is supported by a sturdy, black steel frame that allows the seat to lock securely in place and for the wood slats to be screwed to the frame, rather than riveted so they can be replaced in the unlikely event that a piece goes missing.","Replaceable non-marring foot glides also accompany each chair so you don\'t have to worry about damaging your floors or any damage being done to your chairs if you choose to use them on a patio or concrete surfaces.","But what good would our French Bistro Folding Chairs be if they weren\'t built with commercial-grade qualities?","We know how precious keeping storage areas clear can be so when you\'re not using these chairs, they easily fold up to only 2\'\' thick so you can save every bit of space you need and they only weigh 9 lbs.","Looking to pair these chairs with a table to complete the look?","Take a look at our French Bistro Folding Table and Chair Set!"]', 'specifications' => '{"Special Order Item":"No","UPC":"850004346051","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 50 or more","Can ship FedEx?":"Yes","Brand":"Titan Event Furniture\\u2122","Color":"Brown","Material":"Wood","Commercial-Grade?":"Yes","Folded Dimensions":"36.5\\" x 15.5\\" x 2.25\\"","Overall Height":"31\'\'","Overall Width":"15\'\'","Overall Length \\/ Depth":"17.5\'\'","Recommended Seating":"1","Seat Height":"18\'\'","Seat Size":"15\'\' x 11\'\'","Ships Assembled?":"Yes","Has Arms":"No","Product Warranty":"1 Year","Item Weight":"9 lbs.","Weight Capacity":"364 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"Are French Bistro Folding Chairs suitable for outdoor use?","answer":"Yes! These chairs are great for outdoor use. We just recommend storing them in a climate-controlled area when they\\u2019re not being used."},{"question":"Are French Bistro Folding Chairs durable?","answer":"Yes! Our French Bistro Chairs feature a commercial-grade steel frame and a weight capacity of 364 lbs, ensuring enhanced durability and long-lasting performance."}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 10:17:48', 'updated_at' => '2026-06-18 23:13:35'],
            ['id' => 211, 'product_category_id' => 3, 'name' => 'French Bistro Folding Table and Chair Set', 'slug' => 'french-bistro-folding-table-and-chair-set', 'sku' => 'BISTRO48SETBDL', 'brand' => 'Titan Event Furniture™', 'price' => 93.97, 'stock' => 100, 'image' => 'images/products/french-bistro-folding-table-and-chair-set/9fa83f4322f4.png', 'gallery' => '["images\\/products\\/french-bistro-folding-table-and-chair-set\\/9fa83f4322f4.png","images\\/products\\/french-bistro-folding-table-and-chair-set\\/f5aeb0e22acc.png","images\\/products\\/french-bistro-folding-table-and-chair-set\\/4e10b46dfee7.png","images\\/products\\/french-bistro-folding-table-and-chair-set\\/01e877a23a1b.png","images\\/products\\/french-bistro-folding-table-and-chair-set\\/a45010c80644.png","images\\/products\\/french-bistro-folding-table-and-chair-set\\/a2fa2269e3d3.png","images\\/products\\/french-bistro-folding-table-and-chair-set\\/cf85b51fc632.png"]', 'description' => 'The French Bistro Folding Table and Chair set is the perfect combination to turn your patio or backyard into a Parisian oasis.', 'features' => '["The French Bistro Folding Table and Chair set is the perfect combination to turn your patio or backyard into a Parisian oasis.","If you\'re a cafe, bistro, pub or brewery owner, consider buying this set in bulk and providing a unique and warm seating option for your customers.","Let\'s talk specs.","The chair can hold up to 364 pounds while the table can easily handle that pot roast with a robust weight rating of 165 pounds.","Additionally, The 28.5\'\' height and 21.25\'\' x 21.75\'\' tabletop surface creates ample space for 2 and when the season\'s over, both the French Bistro Folding Chairs and tables easily fold up and only weigh a combined 31 lbs. *Each set ships with a single table and 2 French Bistro Folding Chairs.","Some assembly required for the Bistro Folding Table*"]', 'specifications' => '{"UPC":"850004346068","Free Shipping Deal Type":"Free Shipping","Can ship