            ['id' => 233, 'product_category_id' => 13, 'name' => '72\'\' Round Plastic Folding Table', 'slug' => '72-round-plastic-folding-table', 'sku' => 'PFT2-71R', 'brand' => 'Titan Event Furniture™', 'price' => 253.99, 'stock' => 100, 'image' => 'images/products/72-round-plastic-folding-table/e8fa8653a22c.jpg', 'gallery' => '["images\\/products\\/72-round-plastic-folding-table\\/e8fa8653a22c.jpg","images\\/products\\/72-round-plastic-folding-table\\/a5903b8883da.png","images\\/products\\/72-round-plastic-folding-table\\/030b693d2987.jpg","images\\/products\\/72-round-plastic-folding-table\\/0fcb6a4bb566.jpg","images\\/products\\/72-round-plastic-folding-table\\/a46b11aae9e5.jpg"]', 'description' => 'TitanPRO™ 72\'\' Round Plastic Folding Table.', 'features' => '["TitanPRO\\u2122 72\'\' Round Plastic Folding Table.","Commercial-grade quality.","High-density polyethylene.","Suitable for indoor or outdoor use.","Standard 2\'\' tabletop thickness.","Standard 2\'\' tabletop thickness easily accepts skirting","Smooth, Round Edges","Thick 16 gauge powder coated steel legs","Safety Gravity Ring Gravity-Lock Technology","Non-marring feet glides","Overall Width: 72\'\'","Overall Height: 30\'\'","Table Top Thickness: 2\'\'"]', 'specifications' => '{"Special Order Item":"No","UPC":"850004346563","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 10 or more","Can ship FedEx?":"No","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Color":"Granite White","Material":"High Density Polyethylene","Shape":"Round","Commercial-Grade?":"Yes","Folded Dimensions":"2\'\'x71\'\'","Overall Length \\/ Depth":"71\'\'","Overall Height":"29\'\'","Overall Width":"71\'\'","Recommended Tablecloth Size":"120\'\' Rd, 132\'\' Rd.","Recommended Seating":"10","Ships Assembled?":"Yes","Stackable?":"Yes","Product Warranty":"3 Years","Weight Capacity":"500+ lbs.","Item Weight":"74 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"Does this table ship assembled?","answer":"Yes, the TitanPRO ships fully assembled. No setup is required beyond unfolding the legs before first use. Bulk orders of 10 or more qualify for free shipping deals, and large orders can be quoted for additional wholesale pricing."},{"question":"How does the TitanPRO\\u2122 compare to tables sold at Home Depot or Costco?","answer":"Consumer-grade plastic folding tables are typically built with 18-gauge steel legs and thinner tabletop cores designed for occasional home use. The TitanPRO\\u2122 uses 16-gauge legs, commercial-grade HDPE, and gravity-lock safety rings engineered for the frequency and load demands of rental and venue operations. The 3-year commercial warranty reflects that difference."}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:31:08', 'updated_at' => '2026-06-18 11:31:08'],
            ['id' => 234, 'product_category_id' => 13, 'name' => 'Heavy Duty Birchwood Folding Banquet Table - 48" Round', 'slug' => 'heavy-duty-birchwood-folding-banquet-table-48-round', 'sku' => 'HD5-48R', 'brand' => 'Titan Event Furniture™', 'price' => 124.99, 'stock' => 100, 'image' => 'images/products/heavy-duty-birchwood-folding-banquet-table-48-round/925e5f685df9.jpg', 'gallery' => '["images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/925e5f685df9.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/fd70b8909b34.png","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/bbcc532dfe29.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/fdec00a60951.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/54e99b85f403.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/9e3d0982a733.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/d0009c82cf87.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/4e95ebb5286d.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/e4bfd5691101.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/24c93f8037a3.jpg","images\\/products\\/heavy-duty-birchwood-folding-banquet-table-48-round\\/5f36c1f22a94.jpg"]', 'description' => 'Built under the TitanPRO™ Heavy Duty Birchwood standard — the most durable wood folding table line in the event industry — this 48" round seats 4 to 6 guests and is built to outlast lighter-duty alternatives in rental fleets and venue inventories.', 'features' => '["Built under the TitanPRO\\u2122 Heavy Duty Birchwood standard \\u2014 the most durable wood folding table line in the event industry \\u2014 this 48\\" round seats 4 to 6 guests and is built to outlast lighter-duty alternatives in rental fleets and venue inventories.","If you\'re seeking the most durable wood folding table in the market at wholesale prices, look no further than our TitanPRO 48\'\' Round Heavy Duty Birchwood Folding Table.","It doesn\'t matter if you\'re a venue owner, party rental company, school, church or hosting a backyard wrestling event with the Dudley Boys, this table will last through the rigors of time.","All you need to do is pop the ultra sturdy steel gauge wishbone legs open and 4-6 of your guests can comfortably sit around the most secure wood folding table in the event industry.","With some plywood folding tables, you may worry about chipping or the occasional splinter but there\'s no need to fret with the 4 coat polyurethane finish top that might let a rib eye steak slide off it if you\'re not keeping an eye out.","Thick and rugged metal edging accompanies the sleek wood top to further prevent damage to the table when stacking, rolling or storing.","Commercial grade and event ready with no assembly required, buy our 48\'\' Round Heavy Duty Birchwood Folding Tables in bulk and outfit your venue for years to come!Round tables change how a room feels.","Where rectangular banquet tables create rows, 48\\" rounds create conversations \\u2014 guests face each other rather than a wall of backs, and the room reads as warmer and more social.","For wedding venues, banquet halls, restaurants, and event rental operations, that distinction matters when clients are choosing between layouts.","The TitanPRO\\u2122 Heavy Duty Birchwood line exists specifically for operations that want to offer that experience without compromising on the construction durability that commercial use demands.","Every table in the Heavy Duty Birchwood line starts with a birchwood core, a hardwood chosen for its strength-to-weight ratio and its ability to hold a finish cleanly through repeated commercial use.","On the TitanPRO\\u2122, that finish is applied in four coats of polyurethane, producing a surface that resists moisture, staining, and everyday wear significantly longer than the single or double-coat finishes common on lower-price alternatives.","Metal edge banding wraps the full perimeter, absorbing the contact stress at the table\'s most vulnerable point during stacking, transport, and storage, keeping tables in clean, rentable condition over a long operational life.","Each birchwood top carries natural color and grain variation, so no two tables are precisely alike.","Steel wishbone legs fold flat and lock open securely during use, keeping the table stable under full loading at standard 30\\" banquet height.","At 47 lbs. and 48\\" in diameter, the TitanPRO\\u2122 Heavy Duty Birchwood 48\\" Round seats 4 to 6 guests comfortably and fits standard 90\\" round tablecloths off the shelf.","Tables stack for efficient warehouse storage and transport, and the TitanPRO\\u2122 Universal Table Dolly is the purpose-built companion for operations moving large quantities between events.","Ships fully assembled with no setup required on arrival."]', 'specifications' => '{"Special Order Item":"No","UPC":"850004346204","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 10 or more","Can ship FedEx?":"Yes","Brand":"Titan Event Furniture\\u2122","Material":"Birchwood","Size":"48\'\'","Commercial-Grade?":"Yes","Overall Height":"30\'\'","Overall Width":"48\'\'","Ships Assembled?":"Yes","Stackable?":"Yes","Product Warranty":"2 Year Warranty","Item Weight":"47 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"How many people does a 48\\" round table seat?","answer":"A 48\\" round table comfortably seats 4 to 6 guests. Four is the standard for a relaxed setting with adequate elbow room; six works in tighter configurations."},{"question":"What size tablecloth fits a 48\\" round table?","answer":"For a floor-length drop, use a 90\\" round tablecloth. For a shorter mid-length drop, a 72\\" round works well \\u2014 both sizes are available on EventStable.com."},{"question":"Is birchwood durable enough for commercial use?","answer":"Yes. Birchwood is a hardwood with strong surface durability, and the four-coat polyurethane finish and metal edge banding extend that protection through years of stacking, transport, and regular commercial use."},{"question":"Does this table require assembly?","answer":"No. Ships fully assembled \\u2014 unfold the legs and it\'s ready to use."}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:31:21', 'updated_at' => '2026-06-18 11:37:59'],
