            ['id' => 250, 'product_category_id' => 12, 'name' => '32.5\'\' x 67.5\'\' Brown Rattan Plastic Folding Table', 'slug' => '325-x-675-brown-rattan-plastic-folding-table', 'sku' => 'ES-FC1002', 'brand' => 'Fifth Function', 'price' => 150.79, 'stock' => 100, 'image' => 'images/products/325-x-675-brown-rattan-plastic-folding-table/dc3f03812e8c.jpg', 'gallery' => '["images\\/products\\/325-x-675-brown-rattan-plastic-folding-table\\/dc3f03812e8c.jpg","images\\/products\\/325-x-675-brown-rattan-plastic-folding-table\\/10ae306d8267.jpg","images\\/products\\/325-x-675-brown-rattan-plastic-folding-table\\/7e01624169c3.jpg"]', 'description' => 'Combine comfort and style for your guests when they sit at our Brown Rattan Plastic Folding Table.', 'features' => '["Combine comfort and style for your guests when they sit at our Brown Rattan Plastic Folding Table.","Use it indoors or outdoors, the rattan edge adds a rustic and durable look to any sitting area at your venue.","The tabletop is stain resistant and water proof so you\'ll go years without noticing any wear and tear.","Other must have features include a 1\\/2\'\' dia. umbrella hole that allows convenient shade to hide from all harmful UV rays, powder coated steel frame that provides extra stability and protective floor caps so that anything causing a mark are those dancing shoes."]', 'specifications' => '{"Special Order Item":"No","Free Shipping Deal Type":"Free Shipping","Can ship FedEx?":"Yes","Brand":"Fifth Function","Color":"Brown","Shape":"Rectangle","Commercial-Grade?":"Yes","Legs":"4","Overall Length \\/ Depth":"67.5\'\'","Overall Height":"28.75\'\'","Overall Width":"32.5\'\'","Recommended Seating":"6-8","Ships Assembled?":"Yes","Weight Capacity":"300+ lbs.","Item Weight":"23 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:37:28', 'updated_at' => '2026-06-18 11:37:28'],
            ['id' => 251, 'product_category_id' => 12, 'name' => 'Plastic Folding Table - 8\'x30\'\' banquet', 'slug' => 'plastic-folding-table-8x30-banquet', 'sku' => 'PFT2-3096', 'brand' => 'Titan Event Furniture™', 'price' => 144.99, 'stock' => 100, 'image' => 'images/products/plastic-folding-table-8x30-banquet/48e6790d9da1.jpg', 'gallery' => '["images\\/products\\/plastic-folding-table-8x30-banquet\\/48e6790d9da1.jpg","images\\/products\\/plastic-folding-table-8x30-banquet\\/8026a9f9db18.jpg","images\\/products\\/plastic-folding-table-8x30-banquet\\/c140ce754126.png","images\\/products\\/plastic-folding-table-8x30-banquet\\/614555379aaf.jpg","images\\/products\\/plastic-folding-table-8x30-banquet\\/c8be13309158.png","images\\/products\\/plastic-folding-table-8x30-banquet\\/88688c3776bb.png","images\\/products\\/plastic-folding-table-8x30-banquet\\/8118a1aff1ab.jpg","images\\/products\\/plastic-folding-table-8x30-banquet\\/adbbdf2d403f.jpg"]', 'description' => 'The TitanPRO™ 8\' x 30" plastic folding banquet table seats 8 to 10 guests and is built for the load and frequency demands of commercial operations.', 'features' => '["The TitanPRO\\u2122 8\' x 30\\" plastic folding banquet table seats 8 to 10 guests and is built for the load and frequency demands of commercial operations.","High-density polyethylene construction, 16-gauge powder-coated steel legs, a 500+ lb. weight capacity, and non-marring floor glides deliver the durability rental fleets, event venues, hotels, and schools require.","Standard 2\'\' tabletop thickness easily accepts skirting","Smooth, Round Edges","Thick 16 gauge powder coated steel legs","Safety Gravity Ring Gravity-Lock Technology","Non-marring feet glides","Overall Width: 30\'\'","Overall Length: 8\'","Overall Height: 30\'\'","Table Top Thickness: 2\'\'","Seats 8 to 10 guests and covers the widest range of event formats. At 8\' x 30\\", this is the standard large-format banquet configuration for seated dinners, buffet lines, conference layouts, and vendor setups \\u2014 the single table size that handles the most event types in a commercial rental or venue inventory.","Built to last through years of heavy commercial use. High-density polyethylene construction and 16-gauge powder-coated steel legs give this table the structural durability to handle repeated setups, heavy loads, and everyday wear without warping, rusting, or degrading over time.","Locks open securely so every event runs safely. Gravity-lock safety rings engage automatically when legs are deployed, keeping the table stable under shifting weight and eliminating the risk of unexpected leg collapse during service or setup.","Works with the tablecloths and skirting you already own. The 2\\" standard-thickness tabletop and 30\\" height are sized to industry standard, so existing linens fit correctly and skirting clips attach without adapters or workarounds.","Protects your venue floors at every event. Non-marring floor glides on all four feet prevent scratching on hardwood, vinyl, concrete, and polished surfaces, reducing floor damage and the associated repair costs over the life of your inventory."]', 'specifications' => '{"Special Order Item":"No","UPC":"850004346419","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 10 or more","Can ship FedEx?":"No","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Color":"Granite White","Material":"High Density Polyethylene","Shape":"Rectangle","Size":"8\' x 30\'\'","Commercial-Grade?":"Yes","Folded Dimensions":"1.75\'\'","Overall Length \\/ Depth":"30\'\'","Overall Height":"29\'\'","Overall Width":"96\'\'","Recommended Tablecloth Size":"60\'\'x126\'\', 90\'\'x156\'\'","Recommended Seating":"8","Ships Assembled?":"Yes","Product Warranty":"3 Years","Weight Capacity":"1000 lbs.","Item Weight":"41","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"Does this table ship assembled?","answer":"Yes, the TitanPRO ships fully assembled. No setup is required beyond unfolding the legs before first use. Bulk orders of 10 or more qualify for free shipping deals, and large orders can be quoted for additional wholesale pricing."},{"question":"How does the TitanPRO\\u2122 compare to tables sold at Home Depot or Costco?","answer":"Consumer-grade plastic folding tables are typically built with 18-gauge steel legs and thinner tabletop cores designed for occasional home use. The TitanPRO\\u2122 uses 16-gauge legs, commercial-grade HDPE, and gravity-lock safety rings engineered for the frequency and load demands of rental and venue operations. The 3-year commercial warranty reflects that difference."},{"question":"How many people does an 8-foot folding table seat?","answer":"An 8\' x 30\\" banquet table seats 8 comfortably and up to 10 in tighter configurations."},{"question":"What size tablecloth fits an 8-foot banquet table?","answer":"For a full floor-length drop, use a 60\\" x 126\\" tablecloth. For a mid-length drop that covers the legs, a 60\\" x 102\\" works well. Both sizes are available on EventStable.com and are designed specifically for 8\' banquet table dimensions."},{"question":"Is this table suitable for outdoor use?","answer":"Yes. The HDPE top resists moisture and UV exposure, and the powder-coated steel legs resist rust under normal outdoor conditions. Storing tables indoors between events will extend their lifespan significantly and is recommended for any commercial operation."},{"question":"Does the 8\' table ship assembled?","answer":"Yes, the TitanPRO\\u2122 ships fully assembled. No setup is required beyond unfolding the legs before first use. Bulk orders of 10 or more qualify for wholesale pricing and free shipping."}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:37:36', 'updated_at' => '2026-06-18 11:37:36'],
            ['id' => 252, 'product_category_id' => 12, 'name' => '30\'\' x 96\'\' Plastic Bi-Folding Table', 'slug' => '30-x-96-plastic-bi-folding-table', 'sku' => 'PFT2-3096FIH', 'brand' => 'Titan Event Furniture™', 'price' => 155.25, 'stock' => 100, 'image' => 'images/products/30-x-96-plastic-bi-folding-table/7119ee95f128.jpg', 'gallery' => '["images\\/products\\/30-x-96-plastic-bi-folding-table\\/7119ee95f128.jpg","images\\/products\\/30-x-96-plastic-bi-folding-table\\/a34bf8fbbcdf.jpg","images\\/products\\/30-x-96-plastic-bi-folding-table\\/13cac2447fa6.jpg","images\\/products\\/30-x-96-plastic-bi-folding-table\\/e7d8bd308ae6.jpg","images\\/products\\/30-x-96-plastic-bi-folding-table\\/f372b14b7137.jpg"]', 'description' => 'Our 30\'\' x 96\' Bi-Folding Tables got the TitanPRO™ treatment along with all of our other plastic folding tables for sale.', 'features' => '["Our 30\'\' x 96\' Bi-Folding Tables got the TitanPRO\\u2122 treatment along with all of our other plastic folding tables for sale.","What that means for you is an updated durable stain resistant blow molded top and sturdy frame that will refuse to break down from season to season.","The blow molded top is super low maintenance and cleans easily, so you can spend more time on the more important details like planning your next event.","This 8 ft. fold in half portable table has legs that lock in place in a SNAP with the leg locking system for easy set-ups.","This table isn\'t just meant for party rental companies or event venues.","Are you a weekend warrior?","Use this table at your next garage sale, tailgate or as a temporary seating solution for the martians on Thanksgiving or set it up in a permanent location for everyday use."]', 'specifications' => '{"Special Order Item":"No","UPC":"850004346426","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 10 or more","Can ship FedEx?":"Yes","Brand":"Titan Event Furniture\\u2122","Color":"Granite White","Material":"Plastic","Shape":"Rectangle","Commercial-Grade?":"Yes","Overall Length \\/ Depth":"96\'\'","Overall Height":"30\'\'","Overall Width":"30\'\'","Ships Assembled?":"Yes","Stackable?":"Yes","Product Warranty":"3 Years","Weight Capacity":"600 lbs.","Item Weight":"45 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:37:41', 'updated_at' => '2026-06-19 03:16:11'],
