            ['id' => 254, 'product_category_id' => 12, 'name' => 'Plastic Folding Table - 6\' x 30\'\' Banquet', 'slug' => 'plastic-folding-table-6-x-30-banquet', 'sku' => 'PFT36-3072', 'brand' => 'Titan Event Furniture™', 'price' => 79.49, 'stock' => 100, 'image' => 'images/products/plastic-folding-table-6-x-30-banquet/f63d8aa7f918.jpg', 'gallery' => '["images\\/products\\/plastic-folding-table-6-x-30-banquet\\/f63d8aa7f918.jpg","images\\/products\\/plastic-folding-table-6-x-30-banquet\\/7a70411c1c5b.jpg","images\\/products\\/plastic-folding-table-6-x-30-banquet\\/7f24c5e34d3c.jpg","images\\/products\\/plastic-folding-table-6-x-30-banquet\\/829fc32501b8.jpg","images\\/products\\/plastic-folding-table-6-x-30-banquet\\/e9b8051f722b.png","images\\/products\\/plastic-folding-table-6-x-30-banquet\\/1e822bb99f17.jpg"]', 'description' => 'The TitanPRO™ 6\' x 30" commercial plastic folding banquet table is built for the frequency and load demands of rental fleets, event venues, hotels, and schools.', 'features' => '["The TitanPRO\\u2122 6\' x 30\\" commercial plastic folding banquet table is built for the frequency and load demands of rental fleets, event venues, hotels, and schools.","High-density polyethylene construction, 16-gauge powder-coated steel legs, and a 500+ lb. weight capacity deliver the durability professional operations require","Standard 2\'\' tabletop thickness easily accepts skirting","Smooth, Round Edges","Thick 16 gauge powder coated steel legs","Safety Gravity Ring Gravity-Lock Technology","Non-marring feet glides","Overall Width: 30\'\'","Overall Length: 6\'","Overall Height: 30\'\'","Table Top Thickness: 2\'\'"]', 'specifications' => '{"Special Order Item":"No","UPC":"850004346037","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 10 or more","Can ship FedEx?":"No","Country of Manufacture":"Thailand","Brand":"Titan Event Furniture\\u2122","Color":"Granite White","Material":"High Density Polyethylene","Shape":"Rectangle","Size":"6\' x 30\'\'","Commercial-Grade?":"Yes","Overall Length \\/ Depth":"30\'\'","Overall Height":"29\'\'","Overall Width":"72\'\'","Recommended Tablecloth Size":"60\'\'x102\'\', 60\'\'x126\'\', 90\'\'x132","Recommended Seating":"6","Ships Assembled?":"Yes","Product Warranty":"3 Years","Weight Capacity":"500+ lbs.","Item Weight":"31","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[{"question":"How much weight can the TitanPRO\\u2122 6\' x 30\\" table hold?","answer":"The TitanPRO\\u2122 is rated for 500+ lbs. of static weight capacity. That comfortably covers full buffet setups, place settings for 6 to 8 guests, centerpieces, and display equipment. The 16-gauge steel legs and gravity-lock rings are what make that rating meaningful in real commercial use, not just in lab conditions."},{"question":"How many people does a 6-foot banquet table seat?","answer":"A 6\' x 30\\" banquet table seats 6 comfortably and up to 8 in tighter configurations. For seated dinner service, 6 guests is the standard recommendation to allow enough elbow room and space for place settings."},{"question":"Is this table suitable for outdoor use?","answer":"Yes. The high-density polyethylene top resists moisture and UV exposure, and the powder-coated steel legs resist rust under normal outdoor conditions. It is not rated for permanent outdoor storage, so storing tables indoors between events will extend their lifespan significantly."},{"question":"Does this table ship assembled?","answer":"Yes, the TitanPRO ships fully assembled. No setup is required beyond unfolding the legs before first use. Bulk orders of 10 or more qualify for free shipping deals, and large orders can be quoted for additional wholesale pricing."},{"question":"How does the TitanPRO\\u2122 compare to tables sold at Home Depot or Costco?","answer":"Consumer-grade plastic folding tables are typically built with 18-gauge steel legs and thinner tabletop cores designed for occasional home use. The TitanPRO\\u2122 uses 16-gauge legs, commercial-grade HDPE, and gravity-lock safety rings engineered for the frequency and load demands of rental and venue operations. The 3-year commercial warranty reflects that difference."}]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:37:51', 'updated_at' => '2026-06-18 11:37:51'],
            ['id' => 255, 'product_category_id' => 12, 'name' => 'Plastic TV Dinner Table', 'slug' => 'plastic-tv-dinner-table', 'sku' => 'PFT2-TVDT', 'brand' => 'Titan Event Furniture™', 'price' => 46.99, 'stock' => 100, 'image' => 'images/products/plastic-tv-dinner-table/e8dc2f96320a.jpg', 'gallery' => '["images\\/products\\/plastic-tv-dinner-table\\/e8dc2f96320a.jpg","images\\/products\\/plastic-tv-dinner-table\\/555e3011f724.jpg","images\\/products\\/plastic-tv-dinner-table\\/1280223a1f5f.jpg","images\\/products\\/plastic-tv-dinner-table\\/92e475c04203.jpg","images\\/products\\/plastic-tv-dinner-table\\/1a25cd6882fe.jpg","images\\/products\\/plastic-tv-dinner-table\\/3c098ad4052c.jpg","images\\/products\\/plastic-tv-dinner-table\\/634712f516dd.jpg","images\\/products\\/plastic-tv-dinner-table\\/b34f901a2aa9.jpg"]', 'description' => 'Take a break from the hustle and bustle of event season or set up a personable work station on the go, our TV TableTitanPRO™ Plastic TV Dinner Table is one dynamic piece of furniture - and we didn\'t even mention the adjustable heights.', 'features' => '["Take a break from the hustle and bustle of event season or set up a personable work station on the go, our TV TableTitanPRO\\u2122 Plastic TV Dinner Table is one dynamic piece of furniture - and we didn\'t even mention the adjustable heights.","With optional heights of 18.5\\", 25\\" or 29\\", the usage possibilities are endless.","The adjustable height dining option will certainly hold up under duress, from the rythmic banging of the keyboard, frustrations over a 1000 piece puzzle or a place for the little ones to engage in arts and crafts or homework.","Speaking of homework, this can serve as a great alternative to desks for schools looking to create more space in the classroom This commercial-grade dinner table seamlessly folds up when not in use and takes up virtually no storage space in your closet.","In the event that you get some gravy and mashed potatoes on the surface, even the messiest of messes can easily be wiped clean using water and a paper towel, causing no damage to the tabletop.","This is truly a one of a kind all purpose utility table!"]', 'specifications' => '{"Special Order Item":"No","UPC":"850004346587","Free Shipping Deal Type":"Free Shipping","Can ship FedEx?":"No","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Color":"Gray","Material":"Plastic","Shape":"Rectangle","Commercial-Grade?":"Yes","Overall Length \\/ Depth":"19.5\'\'","Overall Height":"18.5\'\', 25\'\' or 29\'\'","Overall Width":"30\'\'","Ships Assembled?":"No","Stackable?":"Yes","Product Warranty":"3 Years","Item Weight":"13 lbs.","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:37:59', 'updated_at' => '2026-06-18 11:37:59'],
