            ['id' => 258, 'product_category_id' => 15, 'name' => 'Plus™ European Plywood Folding Table - 8\' x 30\'\'', 'slug' => 'plus-european-plywood-folding-table-8-x-30', 'sku' => 'WFT5-3096-V2', 'brand' => 'Titan Event Furniture™', 'price' => 210.99, 'stock' => 100, 'image' => 'images/products/plus-european-plywood-folding-table-8-x-30/1ee466afc9be.jpg', 'gallery' => '["images\\/products\\/plus-european-plywood-folding-table-8-x-30\\/1ee466afc9be.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-30\\/6d48be2f9f8c.png","images\\/products\\/plus-european-plywood-folding-table-8-x-30\\/78533f1d6cd7.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-30\\/9a08629461cd.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-30\\/3fda38ad9d16.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-30\\/c7f1f03e58a2.jpg"]', 'description' => '3/4\'\' thick tabletop with 13 layers of European plywood held together by Phenolic Glue.', 'features' => '["3\\/4\'\' thick tabletop with 13 layers of European plywood held together by Phenolic Glue.","16-gauge powder-coated steel tube legs.","Light brown protective stain is applied and triple sealed on top and bottom of table.","Moisture resistant and suitable for outdoor and indoor commercial use.","Sourced from sustainably managed forests."]', 'specifications' => '{"Special Order Item":"No","UPC":"810171063267","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k, Free Shipping on 10 or more","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Color":"Plywood","Material":"3\\/4\'\' Plywood","Shape":"Rectangle","Size":"8\' x 30\'\'","Commercial-Grade?":"Yes","Folded Dimensions":"2.25\'\'","Legs":"16 gauge, powder coated Steel","Overall Length \\/ Depth":"96\'\'","Overall Height":"30\'\'","Overall Width":"30\'\'","Recommended Tablecloth Size":"60\'\'x126\'\', 90\'\'x156\'\'","Recommended Seating":"8","Ships Assembled?":"Yes","Product Warranty":"1 Year Warranty","Weight Capacity":"500+ lbs.","Item Weight":"60","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:38:14', 'updated_at' => '2026-06-18 11:38:14'],
            ['id' => 259, 'product_category_id' => 15, 'name' => 'Plus™ European Plywood Folding Table - 8\' x 48\'\' banquet', 'slug' => 'plus-european-plywood-folding-table-8-x-48-banquet', 'sku' => 'WFT5-4896-V2', 'brand' => 'Titan Event Furniture™', 'price' => 220.49, 'stock' => 100, 'image' => 'images/products/plus-european-plywood-folding-table-8-x-48-banquet/35d24ed91deb.jpg', 'gallery' => '["images\\/products\\/plus-european-plywood-folding-table-8-x-48-banquet\\/35d24ed91deb.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-48-banquet\\/b6c839f9c756.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-48-banquet\\/b9bd2f39d483.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-48-banquet\\/7fd0a227c863.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-48-banquet\\/e66db2223c8c.jpg","images\\/products\\/plus-european-plywood-folding-table-8-x-48-banquet\\/f176be7178cb.jpg"]', 'description' => 'When you\'re ready to enhance your party rental company or event venue inventory, take a look at our latest addition: the Titan Series Plus™ 8\' x 48\'\' "King" Banquet European Plywood Folding Table from EventStable.', 'features' => '["When you\'re ready to enhance your party rental company or event venue inventory, take a look at our latest addition: the Titan Series Plus\\u2122 8\' x 48\'\' \\"King\\" Banquet European Plywood Folding Table from EventStable.","These tables are meticulously crafted from 13-layer plywood, boasting a sturdy \\u00be inch thickness for exceptional durability.","What makes these tables stand out?","We\'ve taken extra measures to ensure longevity and resilience.","Each table undergoes a meticulous process where a light brown protective stain is applied and triple-sealed on both the top and bottom surfaces, providing unparalleled defense against scratches, spills, and general wear and tear.","Even the edges are sealed prior to the application of vinyl or metal edging, offering comprehensive protection from all angles.","In addition to their durability, these tables also exude style and strength.","Featuring 16-gauge powder-coated steel tubing legs in a classic wishbone design, they offer both stability and aesthetic appeal.","The wishbone design not only enhances stability but also prevents guests from bumping their knees, ensuring comfort throughout your event.","Moreover, each leg is equipped with a vinyl floor glide, safeguarding your floors against scratches and damage.","Best of all, these tables will ship free when you order 10 or more, or in combination with thousands of other event products in orders of $5000 or more.","Whether you\'re hosting weddings, parties, conferences, or trade shows, these plywood folding tables are a long-term investment you can rely on seasons to come"]', 'specifications' => '{"Special Order Item":"No","UPC":"810171063281","Can ship FedEx?":"No","Country of Manufacture":"China","Brand":"Titan Event Furniture\\u2122","Material":"3\\/4\'\' Plywood","Shape":"Rectangle","Commercial-Grade?":"Yes","Folded Dimensions":"2.25\'\'","Legs":"16 gauge, powder coated Steel","Overall Length \\/ Depth":"48\'\'","Overall Height":"30\'\'","Overall Width":"96\'\'","Recommended Tablecloth Size":"90\'\'x156\'\'","Recommended Seating":"10","Ships Assembled?":"Yes","Product Warranty":"1 Year Warranty","Weight Capacity":"500+ lbs.","Item Weight":"80","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 11:38:20', 'updated_at' => '2026-06-18 11:38:20'],
