            ['id' => 299, 'product_category_id' => 8, 'name' => 'All Purpose Chair Dolly', 'slug' => 'all-purpose-chair-dolly', 'sku' => 'DOLLY-C105-FC', 'brand' => 'CSP', 'price' => 180.99, 'stock' => 100, 'image' => 'images/products/all-purpose-chair-dolly/ef4ef262164d.jpg', 'gallery' => '["images\\/products\\/all-purpose-chair-dolly\\/ef4ef262164d.jpg","images\\/products\\/all-purpose-chair-dolly\\/aaabebc326b6.jpg","images\\/products\\/all-purpose-chair-dolly\\/afd2d1866294.jpg","images\\/products\\/all-purpose-chair-dolly\\/36e32f8ebf70.jpg","images\\/products\\/all-purpose-chair-dolly\\/6a52608da73c.jpg","images\\/products\\/all-purpose-chair-dolly\\/00575cada0ac.png","images\\/products\\/all-purpose-chair-dolly\\/39b28813836f.png","images\\/products\\/all-purpose-chair-dolly\\/6e3e0d4fc3bf.jpg","images\\/products\\/all-purpose-chair-dolly\\/5e1b3e1dc3f2.png","images\\/products\\/all-purpose-chair-dolly\\/5cbe8f3878f0.png","images\\/products\\/all-purpose-chair-dolly\\/61159eed1d16.png","images\\/products\\/all-purpose-chair-dolly\\/4c1fa7ef3baf.png","images\\/products\\/all-purpose-chair-dolly\\/63710edd1af6.png"]', 'description' => 'Introduce a smart transport and storage solution built with event-furniture professionals in mind: the All-Purpose Chair Dolly.', 'features' => '["Introduce a smart transport and storage solution built with event-furniture professionals in mind: the All-Purpose Chair Dolly.","Designed to streamline the movement of stacking and banquet chairs, this heavy-duty dolly features a powder-coated steel frame and reliable caster wheels that enable fast, stable rolling across venue floors.","As you set up or tear down, the dolly helps you save labor time and reduce physical strain by allowing large quantities of chairs to be shifted with minimal effort.","Beyond just transport, this dolly supports cleaner storage by keeping chairs off the floor and neatly aligned, which helps maintain their finish and protects rental inventory.","Whether you\\u2019re managing a banquet hall, catering operation, hotel event space or church facility, the All-Purpose Chair Dolly offers the durability and functionality to keep your seating logistics efficient and professional."]', 'specifications' => '{"UPC":"302129410716","Can ship FedEx?":"Yes","Country of Manufacture":"China","Brand":"CSP","Color":"Black","Material":"Metal","Commercial-Grade?":"Yes","Ships Assembled?":"No","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 23:24:31', 'updated_at' => '2026-06-19 22:39:26'],
