            ['id' => 302, 'product_category_id' => 8, 'name' => 'Plastic Folding Chair Cart', 'slug' => 'plastic-folding-chair-cart', 'sku' => 'FCCART2', 'brand' => 'Expressway', 'price' => 277.49, 'stock' => 100, 'image' => 'images/products/plastic-folding-chair-cart/4cac0d8bb24a.jpg', 'gallery' => '["images\\/products\\/plastic-folding-chair-cart\\/4cac0d8bb24a.jpg","images\\/products\\/plastic-folding-chair-cart\\/f6d5cb15dc21.png","images\\/products\\/plastic-folding-chair-cart\\/a0962291e94a.jpg","images\\/products\\/plastic-folding-chair-cart\\/04b1d01ae8a5.jpg"]', 'description' => 'Capable of carrying up to 60 Plastic Folding Chairs', 'features' => '["Capable of carrying up to 60 Plastic Folding Chairs","Easily and securely transport up to 60 Plastic Folding Chairs with our powder-coated steel frame Folding Chair Cart.","With little assembly required, this commercial-grade folding chair dolly allows you to store and move more chairs with ease without having to sacrifice durability or the way it maneuvers through tight event spaces.","Each cart contains heavy duty 5\'\' casters with 2 fixed wheels and 2 swivel wheels, along with handles on each end to further enhance your ability to quickly get to from point A to point B.","Whether it\'s inside a wedding venue, convention center or loading up the truck for your party rental company, this Folding Chair Cart will become a dynamic and integral piece of inventory for your company.","Buying in bulk?","This cart ships free when you include it any order over $5k and we offer competitive quantity pricing when you purchase 5 or more.","Easily and securely transport up to 60 Plastic Folding Chairs with our commercial-grade Folding Chair Cart, built with a powder-coated steel frame for durability and smooth handling.","With minimal assembly required, this dolly helps you move and store chairs quickly without sacrificing strength or maneuverability in tight event spaces.","The cart measures 47 \\u00bd\\" in total length with the handles, with an inner length of 37 \\u00bd\\" and an inner width of 18 \\u215c\\", providing a secure fit for your chairs.","Heavy-duty 5\\" casters (2 fixed, 2 swivel) allow for easy rolling, while handles on each end give you full control from any direction.","Whether you\\u2019re setting up inside a wedding venue, a convention center, or loading trucks for your party rental company, this Folding Chair Cart is designed to save time, reduce strain, and keep operations efficient.","This cart ships free with any order over $5,000, and competitive pricing is available when purchasing 5 or more."]', 'specifications' => '{"UPC":"810171061553","Free Shipping Deal Type":"Free Shipping on Tables and Chairs Over $5k","Can ship FedEx?":"Yes","Brand":"Expressway","Color":"Grey","Commercial-Grade?":"Yes","Cart Type":"Folding Chair Cart","Overall Length \\/ Depth":"47 1\\/2\'\'","Overall Height":"75\'\'","Overall Width":"19\'\'","Ships Assembled?":"No","Item Weight":"40 lbs","California Residents":"Click here for Proposition 65 warning"}', 'faq' => '[]', 'default_color' => NULL, 'color_variants' => '[]', 'is_active' => 1, 'created_at' => '2026-06-18 23:24:55', 'updated_at' => '2026-06-19 22:39:26'],
